  {"id":1,"name":"缠枝莲","nameEn":"Interlocking Lotus","category":"qinghua-patterns","subcategory":"植物纹","description":"缠枝莲是青花瓷最经典的纹饰之一，以莲花为主体、卷草为枝蔓，形成连绵不断的S形曲线构图。适用于器物边饰、主题纹带和填充纹样，建议枝蔓间距控制在主花直径的1.2倍以保持节奏感。在离线档案设计中可作为装饰边框或背景纹理使用。","tags":["莲花","卷草","S形曲线","边饰","经典纹样"],"relatedIds":[2,6,14,13],"params":[{"key":"mainColor","label":"主花色","type":"color","value":"#1a3a6b"},{"key":"vineWidth","label":"枝蔓宽度","type":"number","value":"2"},{"key":"density","label":"密度","type":"select","value":"medium"},{"key":"direction","label":"走向","type":"select","value":"horizontal"}],"source":"传统纹饰"},
  {"id":2,"name":"海水江崖","nameEn":"Sea Water & Mountain Cliff","category":"qinghua-patterns","subcategory":"自然纹","description":"海水江崖纹由翻涌的海浪与陡峭的山石组成，象征江山永固。海浪采用层层叠叠的弧线表现，山石以棱角分明的几何形勾勒。常用于大型器物的底部或下腹部位，建议海浪层数不少于三层以体现气势。在档案设计中可转化为底部装饰带。","tags":["海浪","山石","江山","底部装饰","权威象征"],"relatedIds":[1,10,5],"params":[{"key":"waveLayers","label":"浪层数","type":"number","value":"3"},{"key":"cliffHeight","label":"崖高比","type":"number","value":"0.3"},{"key":"colorDepth","label":"色深","type":"select","value":"deep"}],"source":"传统纹饰"},
  {"id":3,"name":"回纹","nameEn":"Meander Pattern","category":"qinghua-patterns","subcategory":"几何纹","description":"回纹由连续的直角折线构成回字形图案，是青花瓷最常用的边饰纹样。其几何特性使其极易数字化复用，建议线宽控制在0.5-1px以保持精致感。回纹可作为网格系统的辅助线或分隔线，在离线档案中适合用作区块间的视觉分隔。","tags":["直角折线","边饰","几何","分隔线","连续纹"],"relatedIds":[5,7,20],"params":[{"key":"unitSize","label":"单元尺寸","type":"number","value":"8"},{"key":"lineWidth","label":"线宽","type":"number","value":"1"},{"key":"variant","label":"变体","type":"select","value":"square"}],"source":"传统纹饰"},
  {"id":4,"name":"折枝牡丹","nameEn":"Branched Peony","category":"qinghua-patterns","subcategory":"植物纹","description":"折枝牡丹以折断的花枝为构图单元，牡丹花头饱满、叶片舒展，不与枝蔓相连而独立成画。适用于器物主体的开光内或独立画幅，建议花头直径占画幅30%-40%以突出主体。在档案设计中可作为独立装饰图标或水印元素。","tags":["牡丹","折枝","独立构图","开光","富贵"],"relatedIds":[1,13,6],"params":[{"key":"bloomSize","label":"花头比例","type":"number","value":"35"},{"key":"petalCount","label":"花瓣数","type":"number","value":"8"},{"key":"orientation","label":"朝向","type":"select","value":"upright"}],"source":"传统纹饰"},
  {"id":5,"name":"云肩","nameEn":"Cloud Collar","category":"qinghua-patterns","subcategory":"器型纹","description":"云肩纹饰源自服饰云肩，在瓷器上表现为环绕器颈的云形装饰带。由多个如意云头相连构成环形，每个云头内可填充花卉或动物纹。建议云头数量取4或8以保持对称，在档案设计中可转化为顶部导航栏的弧形装饰。","tags":["云头","环形","器颈","如意","对称"],"relatedIds":[3,11,20],"params":[{"key":"cloudCount","label":"云头数","type":"number","value":"4"},{"key":"fillPattern","label":"填充纹","type":"select","value":"floral"},{"key":"arcRadius","label":"弧度","type":"number","value":"60"}],"source":"传统纹饰"},
  {"id":6,"name":"卷草纹","nameEn":"Scrollwork","category":"qinghua-patterns","subcategory":"植物纹","description":"卷草纹以连续翻转的螺旋形草叶为特征，是缠枝纹的简化形态。线条流畅自由，可独立使用也可作为辅助纹饰。建议螺旋半径渐变控制在5%-15%之间以保持视觉韵律，在档案设计中适合用作分隔线或背景流动纹理。","tags":["螺旋","草叶","连续","流动","辅助纹"],"relatedIds":[1,7,14],"params":[{"key":"spiralRadius","label":"螺旋半径","type":"number","value":"12"},{"key":"curlDirection","label":"卷曲方向","type":"select","value":"both"},{"key":"leafCount","label":"叶片密度","type":"number","value":"3"}],"source":"传统纹饰"},
  {"id":7,"name":"竹叶纹","nameEn":"Bamboo Leaf Pattern","category":"qinghua-patterns","subcategory":"植物纹","description":"竹叶纹以简笔竹叶为元素，常三五成组点缀于器壁。竹叶形态简洁，用笔利落，是青花瓷中最具文人气质的纹饰。建议叶片倾角在30°-60°之间变化以增加生动感，在档案设计中可作为低频编码的地域暗示元素。","tags":["竹叶","文人","简笔","地域暗示","点缀"],"relatedIds":[6,15,141],"params":[{"key":"leafAngle","label":"叶片倾角","type":"number","value":"45"},{"key":"groupSize","label":"成组数","type":"number","value":"3"},{"key":"opacity","label":"透明度","type":"number","value":"100"}],"source":"传统纹饰"},
  {"id":8,"name":"龙纹","nameEn":"Dragon Pattern","category":"qinghua-patterns","subcategory":"动物纹","description":"龙纹是青花瓷最高等级的纹饰，五爪龙为皇家专用。龙身蜿蜒、鳞甲分明、须发飘动，常与云纹或火珠搭配。建议龙身弯曲不少于三个转折以体现动感，在档案设计中可作为核心视觉锚点或品牌标识元素。","tags":["龙","皇家","五爪","权威","核心纹饰"],"relatedIds":[9,2,10],"params":[{"key":"clawCount","label":"爪数","type":"select","value":"five"},{"key":"bodyTurns","label":"身躯转折","type":"number","value":"3"},{"key":"withCloud","label":"配云纹","type":"select","value":"yes"},{"key":"scale","label":"鳞甲密度","type":"number","value":"5"}],"source":"传统纹饰"},
  {"id":9,"name":"凤纹","nameEn":"Phoenix Pattern","category":"qinghua-patterns","subcategory":"动物纹","description":"凤纹以长尾翎羽为最显著特征，凤首含冠、展翅翘尾，常与牡丹搭配寓意凤穿花。翎羽线条需流畅飘逸，建议尾羽长度为体长的2-3倍。在档案设计中可转化为优雅的装饰性图标或页面顶部装饰元素。","tags":["凤凰","翎羽","凤穿花","祥瑞","优雅"],"relatedIds":[8,4,10],"params":[{"key":"tailRatio","label":"尾羽比","type":"number","value":"2.5"},{"key":"crownType","label":"冠型","type":"select","value":"triple"},{"key":"flightPose","label":"姿态","type":"select","value":"soaring"}],"source":"传统纹饰"},
  {"id":10,"name":"蝙蝠纹","nameEn":"Bat Pattern","category":"qinghua-patterns","subcategory":"动物纹","description":"蝙蝠纹取「蝠」与「福」谐音，是青花瓷中最常见的吉祥纹饰。蝙蝠形态经高度图案化处理，双翅展开呈对称扇形。建议双翅展角在120°-150°之间，在档案设计中可作为角落装饰或吉祥符号点缀。","tags":["蝙蝠","福","吉祥","对称","图案化"],"relatedIds":[8,9,16],"params":[{"key":"wingAngle","label":"展翅角度","type":"number","value":"135"},{"key":"batCount","label":"蝙蝠数","type":"number","value":"5"},{"key":"arrangement","label":"排列","type":"select","value":"scattered"}],"source":"传统纹饰"},
  {"id":11,"name":"如意纹","nameEn":"Ruyi Pattern","category":"qinghua-patterns","subcategory":"器型纹","description":"如意纹源自如意云头，呈心形或灵芝形，常作为边饰或肩部装饰。如意头可单独使用也可串联成带，建议头尾相连时重叠比例为20%-30%。在档案设计中可转化为按钮形状或卡片圆角样式。","tags":["如意","云头","心形","边饰","吉祥"],"relatedIds":[5,12,20],"params":[{"key":"headSize","label":"头尺寸","type":"number","value":"20"},{"key":"overlap","label":"重叠比","type":"number","value":"25"},{"key":"stemLength","label":"柄长","type":"number","value":"10"}],"source":"传统纹饰"},
  {"id":12,"name":"莲瓣纹","nameEn":"Lotus Petal Band","category":"qinghua-patterns","subcategory":"器型纹","description":"莲瓣纹由连续的尖瓣或圆瓣排列成带状，常见于器物肩部或足部。瓣内可填充花卉、八宝等纹饰，瓣间以细线分隔。建议瓣数取偶数以保持对称，在档案设计中可转化为卡片底部装饰或列表项分隔符。","tags":["莲瓣","带状","肩部","足部","填充纹"],"relatedIds":[11,1,16],"params":[{"key":"petalCount","label":"瓣数","type":"number","value":"12"},{"key":"petalShape","label":"瓣形","type":"select","value":"pointed"},{"key":"innerFill","label":"瓣内填充","type":"select","value":"floral"}],"source":"传统纹饰"},
  {"id":13,"name":"宝相花","nameEn":"Baoxiang Flower","category":"qinghua-patterns","subcategory":"植物纹","description":"宝相花是经艺术加工的理想化花卉，融合莲花、牡丹、石榴等多种花卉特征，呈正面放射对称构图。花瓣层叠如轮，中心常饰花蕊或珠纹。建议花瓣层数不少于三层以体现华丽感，在档案设计中适合用作中心装饰或加载动画图形。","tags":["宝相花","放射对称","理想化","华丽","正面花"],"relatedIds":[1,4,14],"params":[{"key":"petalLayers","label":"花瓣层数","type":"number","value":"3"},{"key":"symmetry","label":"对称轴","type":"number","value":"8"},{"key":"centerType","label":"花心样式","type":"select","value":"pearl"}],"source":"传统纹饰"},
  {"id":14,"name":"缠枝菊","nameEn":"Interlocking Chrysanthemum","category":"qinghua-patterns","subcategory":"植物纹","description":"缠枝菊以菊花为主体、卷草为枝蔓，构图方式与缠枝莲类似但花形不同。菊花花瓣细长密集，呈放射状排列。建议花瓣数取16或24以保持规整，在档案设计中可作为秋季主题的装饰元素或网格填充纹样。","tags":["菊花","缠枝","放射","秋季","长寿"],"relatedIds":[1,6,13],"params":[{"key":"petalCount","label":"花瓣数","type":"number","value":"16"},{"key":"petalLength","label":"花瓣长度","type":"number","value":"15"},{"key":"vineStyle","label":"枝蔓风格","type":"select","value":"curved"}],"source":"传统纹饰"},
  {"id":15,"name":"岁寒三友","nameEn":"Three Friends of Winter","category":"qinghua-patterns","subcategory":"植物纹","description":"岁寒三友指松、竹、梅三种植物，象征高洁品格。三者常组合构图，松针浓密、竹叶疏朗、梅枝横斜形成疏密对比。建议三者面积比约为4:3:3以保持视觉平衡，在档案设计中可转化为三栏布局的隐喻或季节主题装饰。","tags":["松竹梅","高洁","文人","组合构图","冬季"],"relatedIds":[7,4,6],"params":[{"key":"ratio","label":"松竹梅比例","type":"text","value":"4:3:3"},{"key":"layout","label":"布局","type":"select","value":"triangular"},{"key":"season","label":"季节表现","type":"select","value":"winter"}],"source":"传统纹饰"},
  {"id":16,"name":"八宝纹","nameEn":"Eight Treasures","category":"qinghua-patterns","subcategory":"吉祥纹","description":"八宝纹由法轮、法螺、宝伞、白盖、莲花、宝瓶、金鱼、盘长八种吉祥物组成，源自佛教八吉祥。每件宝物可独立使用也可组合排列，建议组合时保持等距排列以体现仪式感。在档案设计中可转化为图标集或导航元素。","tags":["八吉祥","佛教","法器","吉祥","图标集"],"relatedIds":[17,12,10],"params":[{"key":"treasureSet","label":"宝物组合","type":"select","value":"full"},{"key":"arrangement","label":"排列方式","type":"select","value":"circular"},{"key":"detailLevel","label":"细节等级","type":"number","value":"2"}],"source":"传统纹饰"},
  {"id":17,"name":"暗八仙","nameEn":"Hidden Eight Immortals","category":"qinghua-patterns","subcategory":"吉祥纹","description":"暗八仙以八仙所持法器代指八仙本人：葫芦、扇子、鱼鼓、花篮、阴阳板、横笛、荷花、宝剑。不画人物只画法器，含蓄而雅致。建议法器间以云纹或飘带相连，在档案设计中可转化为工具栏图标或功能标识。","tags":["八仙","法器","含蓄","道教","工具图标"],"relatedIds":[16,11,20],"params":[{"key":"connector","label":"连接纹","type":"select","value":"cloud"},{"key":"style","label":"表现风格","type":"select","value":"outline"},{"key":"iconSize","label":"图标尺寸","type":"number","value":"24"}],"source":"传统纹饰"},
  {"id":18,"name":"冰梅纹","nameEn":"Ice & Plum Blossom","category":"qinghua-patterns","subcategory":"自然纹","description":"冰梅纹以冰裂纹为地、梅花点缀其间，是康熙青花最具代表性的纹饰。冰裂呈不规则多边形网格，梅花散落其间形成疏密对比。建议冰裂块面大小变化在3:1以上以避免呆板，在档案设计中可同时调用冰裂纹和梅花两个独立元素。","tags":["冰裂","梅花","康熙","疏密对比","冬季"],"relatedIds":[15,121,2],"params":[{"key":"crackDensity","label":"裂纹密度","type":"number","value":"6"},{"key":"plumCount","label":"梅花数","type":"number","value":"5"},{"key":"crackStyle","label":"裂纹风格","type":"select","value":"random"}],"source":"传统纹饰"},
  {"id":19,"name":"蕉叶纹","nameEn":"Banana Leaf Band","category":"qinghua-patterns","subcategory":"植物纹","description":"蕉叶纹以变形芭蕉叶为单元，叶尖朝上排列成带状装饰。叶脉以中脉为轴左右对称，叶内常填以细密纹饰。建议叶宽与间距比为3:1以保持紧凑感，在档案设计中可转化为垂直分隔条或侧边栏装饰。","tags":["蕉叶","带状","叶脉","垂直","对称填充"],"relatedIds":[12,3,6],"params":[{"key":"leafWidth","label":"叶宽","type":"number","value":"20"},{"key":"veinCount","label":"叶脉数","type":"number","value":"5"},{"key":"fillDetail","label":"填充细节","type":"select","value":"fine"}],"source":"传统纹饰"},
  {"id":20,"name":"璎珞纹","nameEn":"Tassel Pendant Pattern","category":"qinghua-patterns","subcategory":"器型纹","description":"璎珞纹源自佛教装饰，由珠串、流苏、花结等元素组成的垂挂式纹饰。在瓷器上表现为环绕器肩的垂珠装饰，珠串长度自上而下渐变。建议珠串数量取6-12条以保持节奏感，在档案设计中可转化为悬垂式导航或下拉装饰。","tags":["璎珞","珠串","垂挂","佛教","流苏"],"relatedIds":[5,16,11],"params":[{"key":"strandCount","label":"珠串数","type":"number","value":"8"},{"key":"beadSize","label":"珠粒大小","type":"number","value":"3"},{"key":"tasselLength","label":"流苏长度","type":"number","value":"40"}],"source":"传统纹饰"},
  {"id":21,"name":"Mandelbox","nameEn":"Mandelbox","category":"fractal-geometry","subcategory":"3D分形","description":"Mandelbox是一种基于折叠操作的3D分形，通过球面折叠和盒形折叠的迭代产生复杂的立方结构。其表面同时呈现锐利棱角与柔和曲面的双重特征，建议迭代次数控制在10-15次以平衡细节与性能。在档案设计中可生成3D装饰图形或背景纹理。","tags":["3D分形","折叠","立方结构","迭代","双重特征"],"relatedIds":[22,23,28],"params":[{"key":"scale","label":"缩放因子","type":"number","value":"2"},{"key":"iterations","label":"迭代次数","type":"number","value":"12"},{"key":"foldType","label":"折叠类型","type":"select","value":"mixed"}],"source":"数学分形"},
  {"id":22,"name":"Mandelbulb","nameEn":"Mandelbulb","category":"fractal-geometry","subcategory":"3D分形","description":"Mandelbulb是Mandelbrot集的三维扩展，使用球坐标中的幂次运算生成。其表面呈现洋葱状的层叠结构和精细的螺旋纹理，建议幂次取8-12以获得最佳视觉效果。在档案设计中可作为3D视觉锚点或科学可视化元素。","tags":["3D分形","Mandelbrot","球坐标","层叠","螺旋纹理"],"relatedIds":[21,23,29],"params":[{"key":"power","label":"幂次","type":"number","value":"8"},{"key":"resolution","label":"分辨率","type":"number","value":"256"},{"key":"viewAngle","label":"视角","type":"number","value":"45"}],"source":"数学分形"},
  {"id":23,"name":"Julia集","nameEn":"Julia Set","category":"fractal-geometry","subcategory":"2D分形","description":"Julia集是复数平面上二次迭代z²+c的逃逸时间分形，参数c的不同取值产生截然不同的形态。当c接近Mandelbrot集边界时产生最精细的丝状结构，建议逃逸半径设为2、最大迭代200次。在档案设计中可生成独特的背景图案或装饰纹理。","tags":["复平面","逃逸时间","丝状结构","参数敏感","2D分形"],"relatedIds":[22,24,37],"params":[{"key":"cReal","label":"c实部","type":"number","value":"-0.7"},{"key":"cImag","label":"c虚部","type":"number","value":"0.27015"},{"key":"maxIter","label":"最大迭代","type":"number","value":"200"}],"source":"数学分形"},
  {"id":24,"name":"Sierpinski三角","nameEn":"Sierpinski Triangle","category":"fractal-geometry","subcategory":"2D分形","description":"Sierpinski三角通过递归去除中心倒三角生成，是自相似分形的经典案例。其几何简洁性与无限细节的矛盾统一恰好呼应青花瓷纹饰的秩序与变化。建议递归深度5-7层以平衡细节与可读性，在档案设计中可转化为三角形网格布局或装饰图案。","tags":["三角形","递归","自相似","简洁","经典分形"],"relatedIds":[25,26,23],"params":[{"key":"depth","label":"递归深度","type":"number","value":"6"},{"key":"rotation","label":"旋转角","type":"number","value":"0"},{"key":"fillMode","label":"填充模式","type":"select","value":"outline"}],"source":"数学分形"},
  {"id":25,"name":"Koch雪花","nameEn":"Koch Snowflake","category":"fractal-geometry","subcategory":"2D分形","description":"Koch雪花由等边三角形每条边递归添加突起生成，其周长无限而面积有限。曲线的精细递归与冰裂纹的随机裂隙形成有趣的对比。建议迭代3-4次以保持可辨识的雪花形态，在档案设计中可替代冰裂纹作为冬季主题的几何化装饰。","tags":["雪花","递归","无限周长","冰裂纹替代","几何"],"relatedIds":[24,18,27],"params":[{"key":"iterations","label":"迭代次数","type":"number","value":"4"},{"key":"baseSize","label":"基础尺寸","type":"number","value":"100"},{"key":"lineWidth","label":"线宽","type":"number","value":"1"}],"source":"数学分形"},
  {"id":26,"name":"Menger海绵","nameEn":"Menger Sponge","category":"fractal-geometry","subcategory":"3D分形","description":"Menger海绵是Sierpinski地毯的三维版本，通过递归去除立方体中心及六个面中心的小立方体生成。其表面积无限而体积趋于零，空洞结构类似瓷器的镂空工艺。建议递归深度3-4层以保持结构可读，在档案设计中可生成3D网格装饰或镂空纹理。","tags":["立方体","镂空","3D分形","递归","表面积无限"],"relatedIds":[24,21,27],"params":[{"key":"depth","label":"递归深度","type":"number","value":"3"},{"key":"cubeSize","label":"立方体尺寸","type":"number","value":"100"},{"key":"renderMode","label":"渲染模式","type":"select","value":"wireframe"}],"source":"数学分形"},
  {"id":27,"name":"Dragon曲线","nameEn":"Dragon Curve","category":"fractal-geometry","subcategory":"2D分形","description":"Dragon曲线通过纸条反复折叠展开生成，其路径在有限空间内无限蜿蜒。曲线的折叠逻辑与青花瓷折枝纹的蜿蜒走势有形式上的共鸣。建议迭代10-14次以获得丰富的细节，在档案设计中可替代卷草纹作为装饰曲线。","tags":["折叠","蜿蜒","纸条","替代卷草","路径分形"],"relatedIds":[25,28,6],"params":[{"key":"iterations","label":"迭代次数","type":"number","value":"12"},{"key":"segmentLength","label":"段长","type":"number","value":"5"},{"key":"turnAngle","label":"转角","type":"number","value":"90"}],"source":"数学分形"},
  {"id":28,"name":"Apollonian垫片","nameEn":"Apollonian Gasket","category":"fractal-geometry","subcategory":"2D分形","description":"Apollonian垫片由三个互切圆的间隙中递归填入更小的圆生成，是圆与圆之间最优雅的填充方式。其圆形嵌套结构与宝相花的层叠花瓣有视觉关联。建议递归深度4-5层以获得精细的圆填充效果，在档案设计中可生成圆形装饰群或气泡状背景。","tags":["圆形","互切","递归填充","宝相花关联","优雅"],"relatedIds":[13,23,29],"params":[{"key":"depth","label":"递归深度","type":"number","value":"5"},{"key":"baseRadius","label":"基础半径","type":"number","value":"100"},{"key":"curvatureMode","label":"曲率模式","type":"select","value":"descartes"}],"source":"数学分形"},
  {"id":29,"name":"L-system","nameEn":"L-System","category":"fractal-geometry","subcategory":"生成系统","description":"L-system通过字符串重写规则生成自相似结构，可模拟植物分枝、海藻生长等自然形态。其规则化生成逻辑与缠枝纹的程式化构图高度契合。建议公理简洁、规则数不超过3条以保持可控性，在档案设计中可程序化生成植物纹饰。","tags":["字符串重写","植物模拟","规则化","程序生成","分枝"],"relatedIds":[30,27,1],"params":[{"key":"axiom","label":"公理","type":"text","value":"F"},{"key":"rules","label":"规则","type":"text","value":"F=F[+F]F[-F]F"},{"key":"angle","label":"转角","type":"number","value":"25.7"},{"key":"iterations","label":"迭代次数","type":"number","value":"4"}],"source":"数学分形"},
  {"id":30,"name":"分形树","nameEn":"Fractal Tree","category":"fractal-geometry","subcategory":"2D分形","description":"分形树通过递归分枝算法生成树状结构，每个枝干末端分裂为两个或多个子枝。分枝角度和缩放比的控制产生从规整到随机的多种树形。建议分枝角度25°-35°、缩放比0.65-0.75以模拟自然树形，在档案设计中可替代竹叶纹作为自然主题装饰。","tags":["树状","递归分枝","自然形态","竹叶替代","生长算法"],"relatedIds":[29,7,15],"params":[{"key":"branchAngle","label":"分枝角","type":"number","value":"30"},{"key":"scaleRatio","label":"缩放比","type":"number","value":"0.7"},{"key":"maxDepth","label":"最大深度","type":"number","value":"8"}],"source":"数学分形"},
  {"id":31,"name":"Hilbert曲线","nameEn":"Hilbert Curve","category":"fractal-geometry","subcategory":"空间填充","description":"Hilbert曲线是一种空间填充曲线，能遍历平面上的每一个点而不交叉。其U形递归结构在有限空间内创造密集的路径覆盖，与回纹的连续折线有形式关联。建议阶数4-6以平衡密度与可辨识度，在档案设计中可生成独特的边框或路径动画。","tags":["空间填充","U形递归","不交叉","回纹关联","路径覆盖"],"relatedIds":[32,3,24],"params":[{"key":"order","label":"阶数","type":"number","value":"5"},{"key":"cellSize","label":"单元格尺寸","type":"number","value":"4"},{"key":"lineWidth","label":"线宽","type":"number","value":"1"}],"source":"数学分形"},
  {"id":32,"name":"Peano曲线","nameEn":"Peano Curve","category":"fractal-geometry","subcategory":"空间填充","description":"Peano曲线是最早被发现的空间填充曲线，使用3×3网格递归生成。其路径密集覆盖整个平面，比Hilbert曲线更加均匀但视觉上更复杂。建议阶数3-4以保持路径可追踪，在档案设计中可生成全屏背景纹理或密集装饰图案。","tags":["空间填充","3×3网格","密集覆盖","均匀","背景纹理"],"relatedIds":[31,24,37],"params":[{"key":"order","label":"阶数","type":"number","value":"3"},{"key":"gridSize","label":"网格尺寸","type":"number","value":"300"},{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"}],"source":"数学分形"},
  {"id":33,"name":"Cantor集","nameEn":"Cantor Set","category":"fractal-geometry","subcategory":"1D分形","description":"Cantor集通过反复去除线段中间三分之一生成，是最简单的分形之一。其「有与无」的交替节奏恰好呼应留白哲学的虚实相生。建议递归5-7层以产生足够的视觉节奏，在档案设计中可转化为水平分隔线的渐变消隐效果。","tags":["一维","去除中间","留白","虚实","节奏"],"relatedIds":[24,160,34],"params":[{"key":"depth","label":"递归深度","type":"number","value":"6"},{"key":"barHeight","label":"条高度","type":"number","value":"3"},{"key":"removeRatio","label":"去除比","type":"number","value":"0.33"}],"source":"数学分形"},
  {"id":34,"name":"Fibonacci螺旋","nameEn":"Fibonacci Spiral","category":"fractal-geometry","subcategory":"黄金比例","description":"Fibonacci螺旋基于斐波那契数列的递增正方形内接四分之一圆生成，其曲率变化遵循黄金比例。螺旋的自然增长逻辑与缠枝纹的蔓延走势高度一致。建议螺旋圈数5-8圈以体现增长感，在档案设计中可替代云肩作为弧形构图框架。","tags":["黄金比例","螺旋","自然增长","缠枝关联","弧形构图"],"relatedIds":[35,62,1],"params":[{"key":"turns","label":"圈数","type":"number","value":"6"},{"key":"startSize","label":"起始尺寸","type":"number","value":"10"},{"key":"direction","label":"方向","type":"select","value":"clockwise"}],"source":"数学分形"},
  {"id":35,"name":"Voronoi图","nameEn":"Voronoi Diagram","category":"fractal-geometry","subcategory":"空间划分","description":"Voronoi图将平面按最近点原则划分为凸多边形区域，其不规则多边形结构与冰裂纹的随机裂隙高度相似。建议种子点数量50-200以获得适中密度的网格，在档案设计中可直接替代冰裂纹作为背景纹理或区域划分框架。","tags":["空间划分","多边形","冰裂纹替代","最近点","区域划分"],"relatedIds":[36,18,121],"params":[{"key":"seedCount","label":"种子点数","type":"number","value":"100"},{"key":"edgeStyle","label":"边缘样式","type":"select","value":"thin"},{"key":"cellFill","label":"单元填充","type":"select","value":"none"}],"source":"数学分形"},
  {"id":36,"name":"Delaunay三角","nameEn":"Delaunay Triangulation","category":"fractal-geometry","subcategory":"空间划分","description":"Delaunay三角剖分是Voronoi图的对偶图，将散点连接为满足空圆性质的三角网格。其三角化结构与回纹的几何秩序形成互补，建议与Voronoi叠加使用以产生双层纹理。在档案设计中可生成三角网格背景或3D地形的线框表达。","tags":["三角剖分","Voronoi对偶","空圆性质","网格","线框"],"relatedIds":[35,24,26],"params":[{"key":"pointCount","label":"点数","type":"number","value":"80"},{"key":"showCircumcircle","label":"显示外接圆","type":"select","value":"no"},{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"}],"source":"数学分形"},
  {"id":37,"name":"Perlin噪声","nameEn":"Perlin Noise","category":"fractal-geometry","subcategory":"噪声函数","description":"Perlin噪声生成连续平滑的伪随机值，广泛用于模拟自然纹理如云层、地形、木纹等。其可控的随机性恰好介于传统纹饰的程式化与冰裂纹的随机性之间。建议octaves取4-6以获得丰富的细节层次，在档案设计中可生成有机感的背景纹理。","tags":["伪随机","连续平滑","自然纹理","可控随机","octaves"],"relatedIds":[38,23,35],"params":[{"key":"octaves","label":"八度数","type":"number","value":"5"},{"key":"persistence","label":"持续度","type":"number","value":"0.5"},{"key":"scale","label":"缩放","type":"number","value":"0.01"}],"source":"数学分形"},
  {"id":38,"name":"分形火焰","nameEn":"Fractal Flame","category":"fractal-geometry","subcategory":"迭代函数","description":"分形火焰是IFS的视觉化扩展，通过多个非线性变换的随机迭代产生火焰般的有机形态。其色彩渐变和流动感与窑变釉色的不可预测性形成呼应。建议变换数3-6个、迭代10万次以上以获得细腻效果，在档案设计中可生成抽象装饰图形。","tags":["IFS","火焰","窑变关联","非线性变换","有机形态"],"relatedIds":[39,37,22],"params":[{"key":"transformCount","label":"变换数","type":"number","value":"4"},{"key":"iterations","label":"迭代次数","type":"number","value":"100000"},{"key":"colorMode","label":"色彩模式","type":"select","value":"gradient"}],"source":"数学分形"},
  {"id":39,"name":"IFS迭代","nameEn":"Iterated Function System","category":"fractal-geometry","subcategory":"迭代函数","description":"IFS通过一组仿射变换的随机迭代生成自相似分形，是分形火焰的数学基础。每个变换包含平移、旋转、缩放参数，通过概率权重控制迭代频率。建议变换数2-5个以保持形态可控，在档案设计中可程序化生成各种自相似装饰图案。","tags":["仿射变换","自相似","概率权重","程序生成","数学基础"],"relatedIds":[38,29,28],"params":[{"key":"transformCount","label":"变换数","type":"number","value":"3"},{"key":"iterations","label":"迭代次数","type":"number","value":"50000"},{"key":"pointSize","label":"点尺寸","type":"number","value":"1"}],"source":"数学分形"},
  {"id":40,"name":"元胞自动机","nameEn":"Cellular Automaton","category":"fractal-geometry","subcategory":"生成系统","description":"元胞自动机通过简单的局部规则产生复杂的全局模式，最著名的是Conway生命游戏和一维规则30。规则30的单行演化产生的混沌图案与窑变的不可预测性有深层关联。建议网格尺寸100×100以上以展现涌现行为，在档案设计中可生成动态背景或演化动画。","tags":["局部规则","涌现","生命游戏","规则30","窑变关联"],"relatedIds":[29,37,33],"params":[{"key":"ruleNumber","label":"规则号","type":"number","value":"30"},{"key":"gridWidth","label":"网格宽度","type":"number","value":"200"},{"key":"initialState","label":"初始状态","type":"select","value":"single"}],"source":"数学分形"},
  {"id":41,"name":"技术网格","nameEn":"Technical Grid","category":"offline-archive","subcategory":"基础框架","description":"技术网格是离线档案美学的骨架元素，由等距水平线和垂直线构成精密的参考网格。网格线建议使用低不透明度5%-10%的蓝色或灰色，线间距8px或12px以呼应12栏网格系统。在档案设计中作为所有其他元素的定位基准层。","tags":["网格","参考线","定位基准","低不透明度","骨架"],"relatedIds":[42,61,181],"params":[{"key":"spacing","label":"线间距","type":"number","value":"12"},{"key":"opacity","label":"不透明度","type":"number","value":"8"},{"key":"color","label":"网格色","type":"color","value":"#1a3a6b"}],"source":"UI设计模式"},
  {"id":42,"name":"裁切标记","nameEn":"Crop Marks","category":"offline-archive","subcategory":"印刷标记","description":"裁切标记是印刷品边缘的L形角标，指示最终裁切位置。在离线档案美学中，裁切标记暗示「未完成」或「正在制作」的状态。建议标记长度8-12px、距边缘3-5px，线宽0.5px以保持精致。在档案设计中可置于画布四角以强化印刷品感。","tags":["裁切","L形","印刷","未完成","角标"],"relatedIds":[43,41,44],"params":[{"key":"markLength","label":"标记长度","type":"number","value":"10"},{"key":"offset","label":"距边缘","type":"number","value":"4"},{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"}],"source":"UI设计模式"},
  {"id":43,"name":"配准标记","nameEn":"Registration Marks","category":"offline-archive","subcategory":"印刷标记","description":"配准标记是印刷中用于对齐各色版的十字圆靶标记，由同心圆和十字线组成。在离线档案美学中，配准标记暗示「多图层对齐」的精确性。建议同心圆3-4层、十字线延伸至标记外，在档案设计中可置于页面中心或四角作为对齐参考。","tags":["配准","十字圆靶","对齐","多图层","精确"],"relatedIds":[42,44,41],"params":[{"key":"ringCount","label":"圆环数","type":"number","value":"3"},{"key":"crossLength","label":"十字线长","type":"number","value":"20"},{"key":"position","label":"位置","type":"select","value":"corners"}],"source":"UI设计模式"},
  {"id":44,"name":"纸质标签","nameEn":"Paper Label","category":"offline-archive","subcategory":"信息载体","description":"纸质标签模拟博物馆藏品标签的外观，包含编号、名称、产地、年代等元数据字段。标签背景为微黄纸色，边框细线，文字等宽排列。建议标签宽度固定、高度随内容自适应，在档案设计中可附着于任何视觉元素旁提供元信息。","tags":["博物馆","元数据","编号","纸色","等宽"],"relatedIds":[45,46,47],"params":[{"key":"bgColor","label":"背景色","type":"color","value":"#f5f0e8"},{"key":"borderWidth","label":"边框宽度","type":"number","value":"1"},{"key":"fontSize","label":"字号","type":"number","value":"10"}],"source":"UI设计模式"},
  {"id":45,"name":"角括号","nameEn":"Corner Brackets","category":"offline-archive","subcategory":"视觉标点","description":"角括号是离线档案美学的标志性装饰元素，由四个L形角标框定内容区域。角括号不闭合四边，只标记四角，暗示「被框选但未封闭」的状态。建议括号线宽1px、内缩8-12px，在档案设计中可框定任何内容区块以增加档案感。","tags":["角标","L形","框选","未封闭","标志性"],"relatedIds":[41,42,61],"params":[{"key":"bracketSize","label":"括号尺寸","type":"number","value":"12"},{"key":"inset","label":"内缩距离","type":"number","value":"8"},{"key":"lineWidth","label":"线宽","type":"number","value":"1"}],"source":"UI设计模式"},
  {"id":46,"name":"信息面板","nameEn":"Info Panel","category":"offline-archive","subcategory":"信息载体","description":"信息面板是位于主体区域侧边的固定宽度面板，用于展示元数据、参数或注释信息。面板宽度建议占画布15%-20%，背景略深于主背景以区分层级。在档案设计中可承载设计参数、色彩数值、纹饰说明等辅助信息。","tags":["侧边栏","元数据","参数","辅助信息","固定宽度"],"relatedIds":[44,47,61],"params":[{"key":"width","label":"面板宽度","type":"number","value":"200"},{"key":"bgOpacity","label":"背景透明度","type":"number","value":"95"},{"key":"position","label":"位置","type":"select","value":"right"}],"source":"UI设计模式"},
  {"id":47,"name":"图标工具栏","nameEn":"Icon Toolbar","category":"offline-archive","subcategory":"交互元素","description":"图标工具栏是位于画布边缘的窄条图标行，模拟设计软件的工具面板。图标使用线性风格，尺寸16-24px，间距8px。建议工具栏宽度占画布3%-5%，仅展示关键操作图标。在档案设计中可暗示「可操作」的交互暗示。","tags":["工具栏","线性图标","窄条","交互暗示","边缘"],"relatedIds":[46,48,49],"params":[{"key":"iconSize","label":"图标尺寸","type":"number","value":"20"},{"key":"iconSpacing","label":"图标间距","type":"number","value":"8"},{"key":"position","label":"位置","type":"select","value":"left"}],"source":"UI设计模式"},
  {"id":48,"name":"进度条","nameEn":"Progress Bar","category":"offline-archive","subcategory":"状态指示","description":"进度条以水平条形显示完成比例，在离线档案美学中暗示「加载中」或「处理中」的状态。建议条高度2-4px、填充色使用钴蓝色域、背景色使用浅灰。在档案设计中可置于页面顶部或底部作为装饰性状态指示。","tags":["进度","加载","状态","钴蓝填充","水平条"],"relatedIds":[49,50,55],"params":[{"key":"barHeight","label":"条高度","type":"number","value":"3"},{"key":"fillColor","label":"填充色","type":"color","value":"#1a3a6b"},{"key":"progress","label":"进度","type":"number","value":"65"}],"source":"UI设计模式"},
  {"id":49,"name":"尺寸标注","nameEn":"Dimension Annotation","category":"offline-archive","subcategory":"技术标注","description":"尺寸标注模拟工程图纸的标注方式，由标注线、端点箭头和数值文字组成。在离线档案美学中，尺寸标注暗示「精确测量」的档案态度。建议标注线使用0.5px细线、数值使用等宽字体8-10px，在档案设计中可标注视觉元素的实际或虚拟尺寸。","tags":["标注","工程图","精确","等宽数值","测量"],"relatedIds":[42,50,41],"params":[{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"},{"key":"fontSize","label":"数值字号","type":"number","value":"9"},{"key":"unit","label":"单位","type":"select","value":"px"}],"source":"UI设计模式"},
  {"id":50,"name":"条形码装饰","nameEn":"Barcode Decoration","category":"offline-archive","subcategory":"数据装饰","description":"条形码装饰将真实条形码的视觉形态转化为装饰元素，由粗细不等的竖线排列组成。在离线档案美学中，条形码暗示「可扫描」「有编码信息」的数字档案属性。建议竖线数30-60条、整体宽度80-120px，在档案设计中可置于页面底部或侧边作为装饰。","tags":["条形码","竖线","编码","可扫描","装饰"],"relatedIds":[51,48,49],"params":[{"key":"barCount","label":"竖线数","type":"number","value":"45"},{"key":"totalWidth","label":"总宽度","type":"number","value":"100"},{"key":"barColor","label":"线条色","type":"color","value":"#1a3a6b"}],"source":"UI设计模式"},
  {"id":51,"name":"二维码装饰","nameEn":"QR Code Decoration","category":"offline-archive","subcategory":"数据装饰","description":"二维码装饰将QR码的视觉形态转化为装饰元素，保留定位图案和模块化方格结构。在离线档案美学中，二维码暗示「可链接」「有数字入口」的离线-在线桥接属性。建议模块尺寸4-6px、整体尺寸80-120px，在档案设计中可置于角落作为功能性装饰。","tags":["二维码","方格","可链接","离线在线","功能性装饰"],"relatedIds":[50,52,53],"params":[{"key":"moduleSize","label":"模块尺寸","type":"number","value":"4"},{"key":"totalSize","label":"总尺寸","type":"number","value":"100"},{"key":"errorLevel","label":"纠错等级","type":"select","value":"M"}],"source":"UI设计模式"},
  {"id":52,"name":"单选按钮","nameEn":"Radio Button","category":"offline-archive","subcategory":"交互元素","description":"单选按钮是圆形选择控件，在离线档案美学中作为装饰性UI碎片使用。选中状态为实心圆、未选中为空心圆，暗示「选项存在但不可操作」的静态展示感。建议圆径12-16px、间距8px，在档案设计中可排列于参数区域旁暗示可配置性。","tags":["单选","圆形","UI碎片","选项","静态展示"],"relatedIds":[53,47,55],"params":[{"key":"circleSize","label":"圆径","type":"number","value":"14"},{"key":"selected","label":"选中状态","type":"select","value":"filled"},{"key":"labelPosition","label":"标签位置","type":"select","value":"right"}],"source":"UI设计模式"},
  {"id":53,"name":"开关控件","nameEn":"Toggle Switch","category":"offline-archive","subcategory":"交互元素","description":"开关控件是胶囊形切换控件，在离线档案美学中暗示「功能可启停」的交互可能。开状态滑块在右、关状态滑块在左，建议胶囊宽度36-44px。在档案设计中可排列于设置面板或参数区域，即使不可交互也传递「可控性」的视觉暗示。","tags":["开关","胶囊形","切换","可控性","设置"],"relatedIds":[52,54,47],"params":[{"key":"capsuleWidth","label":"胶囊宽","type":"number","value":"40"},{"key":"state","label":"状态","type":"select","value":"on"},{"key":"thumbColor","label":"滑块色","type":"color","value":"#ffffff"}],"source":"UI设计模式"},
  {"id":54,"name":"下拉指示器","nameEn":"Dropdown Indicator","category":"offline-archive","subcategory":"交互元素","description":"下拉指示器是倒三角箭头，标记可展开的下拉菜单位置。在离线档案美学中，倒三角暗示「更多选项隐藏在下」的信息层级。建议三角尺寸6-8px、置于文字右侧4px处，在档案设计中可附着于分类标签或筛选器旁。","tags":["下拉","倒三角","展开","信息层级","筛选"],"relatedIds":[52,53,55],"params":[{"key":"triangleSize","label":"三角尺寸","type":"number","value":"6"},{"key":"direction","label":"方向","type":"select","value":"down"},{"key":"offset","label":"偏移","type":"number","value":"4"}],"source":"UI设计模式"},
  {"id":55,"name":"状态指示灯","nameEn":"Status Indicator","category":"offline-archive","subcategory":"状态指示","description":"状态指示灯是小型圆点，通过颜色传达状态信息：绿色=正常、黄色=警告、红色=错误、蓝色=信息。在离线档案美学中，指示灯暗示「系统正在运行」的实时感。建议圆径6-8px，在档案设计中可置于标题旁或面板角落传达状态。","tags":["状态灯","圆点","颜色编码","实时感","系统运行"],"relatedIds":[48,56,52],"params":[{"key":"dotSize","label":"圆径","type":"number","value":"6"},{"key":"status","label":"状态色","type":"select","value":"green"},{"key":"pulse","label":"脉冲动画","type":"select","value":"none"}],"source":"UI设计模式"},
  {"id":56,"name":"迷你图表","nameEn":"Mini Chart","category":"offline-archive","subcategory":"数据可视化","description":"迷你图表是嵌入面板的小型数据可视化，包括迷你折线图、柱状图、饼图等。在离线档案美学中，迷你图表暗示「数据驱动」的理性分析态度。建议图表高度20-30px、宽度60-100px，在档案设计中可置于信息面板内展示参数趋势。","tags":["迷你图","折线","柱状","数据驱动","嵌入式"],"relatedIds":[57,46,48],"params":[{"key":"chartType","label":"图表类型","type":"select","value":"sparkline"},{"key":"height","label":"图表高度","type":"number","value":"24"},{"key":"dataPoints","label":"数据点数","type":"number","value":"12"}],"source":"UI设计模式"},
  {"id":57,"name":"数据表格","nameEn":"Data Table","category":"offline-archive","subcategory":"数据可视化","description":"数据表格以行列结构展示参数和数值，是离线档案美学中最理性的信息载体。表头使用加粗等宽字体、单元格对齐严格、行间以细线分隔。建议字号8-10px、行高20-24px，在档案设计中可展示设计参数、色彩数值、纹饰属性等结构化数据。","tags":["表格","行列","参数","等宽","结构化"],"relatedIds":[56,44,46],"params":[{"key":"fontSize","label":"字号","type":"number","value":"9"},{"key":"rowHeight","label":"行高","type":"number","value":"22"},{"key":"borderStyle","label":"边框样式","type":"select","value":"horizontal"}],"source":"UI设计模式"},
  {"id":58,"name":"面包屑导航","nameEn":"Breadcrumb Navigation","category":"offline-archive","subcategory":"导航元素","description":"面包屑导航以「首页 > 分类 > 子类 > 当前」的路径形式展示层级位置。在离线档案美学中，面包屑暗示「有结构的档案系统」而非扁平页面。建议分隔符使用「/」或「>」，字号10-12px，在档案设计中可置于页面顶部作为层级导航。","tags":["面包屑","层级","路径","档案结构","导航"],"relatedIds":[59,60,46],"params":[{"key":"separator","label":"分隔符","type":"select","value":"/"},{"key":"fontSize","label":"字号","type":"number","value":"11"},{"key":"maxDepth","label":"最大深度","type":"number","value":"4"}],"source":"UI设计模式"},
  {"id":59,"name":"标签页","nameEn":"Tab Panel","category":"offline-archive","subcategory":"导航元素","description":"标签页以顶部标签切换内容区域，在离线档案美学中暗示「多视角查看同一对象」的分析态度。激活标签底部加粗或变色，非激活标签灰显。建议标签宽度和间距统一，在档案设计中可切换同一纹饰的不同参数视图或不同风格方案。","tags":["标签页","切换","多视角","分析","视图"],"relatedIds":[58,60,52],"params":[{"key":"tabCount","label":"标签数","type":"number","value":"3"},{"key":"activeStyle","label":"激活样式","type":"select","value":"underline"},{"key":"tabHeight","label":"标签高度","type":"number","value":"32"}],"source":"UI设计模式"},
  {"id":60,"name":"折叠面板","nameEn":"Accordion Panel","category":"offline-archive","subcategory":"导航元素","description":"折叠面板以可展开/折叠的区块组织内容，在离线档案美学中暗示「信息有层级、可按需展开」的渐进式披露。折叠状态仅显示标题行，展开后显示详细内容。建议标题行高度28-32px，在档案设计中可组织参数面板或说明文档的层级结构。","tags":["折叠","展开","渐进披露","层级","参数面板"],"relatedIds":[59,58,46],"params":[{"key":"headerHeight","label":"标题行高","type":"number","value":"30"},{"key":"iconPosition","label":"图标位置","type":"select","value":"left"},{"key":"animation","label":"动画","type":"select","value":"slide"}],"source":"UI设计模式"},
  {"id":61,"name":"钴蓝色域","nameEn":"Cobalt Blue Range","category":"color-systems","subcategory":"蓝色系","description":"钴蓝色域是青花瓷的核心色彩系统，源自氧化钴在1280°C还原焰中的发色范围。色域从深钴蓝#0d1b3e到浅钴蓝#a8c8e8，覆盖明度梯度约8个色阶。建议主色取#1a3a6b、辅色取#4a7ab5、高光取#a8c8e8，在档案设计中作为全局主色调。","tags":["钴蓝","氧化钴","还原焰","主色调","8色阶"],"relatedIds":[62,69,70],"params":[{"key":"primary","label":"主色","type":"color","value":"#1a3a6b"},{"key":"secondary","label":"辅色","type":"color","value":"#4a7ab5"},{"key":"highlight","label":"高光","type":"color","value":"#a8c8e8"}],"source":"矿物色系"},
  {"id":62,"name":"冰蓝色域","nameEn":"Ice Blue Range","category":"color-systems","subcategory":"蓝色系","description":"冰蓝色域是钴蓝色域向冷灰方向的偏移，色温更冷、饱和度更低，模拟冰面反射的天空色。色域从深冰蓝#1a2a4a到浅冰蓝#c8d8e8，适合方案B的冷灰阶底调。建议与冷灰阶搭配使用以保持色温一致性。","tags":["冰蓝","冷灰","低饱和","方案B","色温冷"],"relatedIds":[61,63,64],"params":[{"key":"primary","label":"主色","type":"color","value":"#1a2a4a"},{"key":"secondary","label":"辅色","type":"color","value":"#5a7a9a"},{"key":"highlight","label":"高光","type":"color","value":"#c8d8e8"}],"source":"算法色系"},
  {"id":63,"name":"暖灰阶","nameEn":"Warm Gray Scale","category":"color-systems","subcategory":"灰阶系统","description":"暖灰阶是方案A的底调色彩系统，模拟成都潮湿雾气中纸张的色调。灰阶带微黄暖调，从#f0eeeb底色到#3a3835深色，覆盖10个色阶。建议背景使用#f0eeeb、文字使用#3a3835、边框使用#d0ccc5，在档案设计中作为方案A的全局灰阶。","tags":["暖灰","方案A","成都雾气","微黄","纸张色"],"relatedIds":[64,61,66],"params":[{"key":"background","label":"背景色","type":"color","value":"#f0eeeb"},{"key":"textColor","label":"文字色","type":"color","value":"#3a3835"},{"key":"border","label":"边框色","type":"color","value":"#d0ccc5"}],"source":"纸质色系"},
  {"id":64,"name":"冷灰阶","nameEn":"Cool Gray Scale","category":"color-systems","subcategory":"灰阶系统","description":"冷灰阶是方案B的底调色彩系统，带蓝灰冷调，模拟数字屏幕的底色。灰阶从#f0f2f5底色到#2a2e35深色，覆盖10个色阶。建议背景使用#f0f2f5、文字使用#2a2e35、边框使用#c5c8d0，在档案设计中作为方案B的全局灰阶。","tags":["冷灰","方案B","蓝灰","屏幕色","数字底调"],"relatedIds":[63,62,66],"params":[{"key":"background","label":"背景色","type":"color","value":"#f0f2f5"},{"key":"textColor","label":"文字色","type":"color","value":"#2a2e35"},{"key":"border","label":"边框色","type":"color","value":"#c5c8d0"}],"source":"算法色系"},
  {"id":65,"name":"单色约束","nameEn":"Monochrome Constraint","category":"color-systems","subcategory":"色彩策略","description":"单色约束是青花瓷色彩的核心策略——仅使用蓝色域+灰阶，不引入任何第二色相。这一约束迫使设计者通过明度、饱和度和纹理的变化创造丰富感。建议蓝色域不超过8个色阶、灰阶不超过10个色阶，在档案设计中作为全局色彩纪律。","tags":["单色","蓝色域","灰阶","色彩纪律","约束即自由"],"relatedIds":[61,63,64],"params":[{"key":"hueRange","label":"色相范围","type":"number","value":"15"},{"key":"maxSteps","label":"最大色阶","type":"number","value":"18"},{"key":"strategy","label":"策略","type":"select","value":"strict"}],"source":"传统美学"},
  {"id":66,"name":"色调反转","nameEn":"Tonal Inversion","category":"color-systems","subcategory":"色彩策略","description":"色调反转将前景与背景的明度关系对调——蓝底白纹替代白底蓝纹。这一操作在保持单色约束的同时产生强烈的视觉冲击，模拟夜间屏幕或底片效果。建议反转后调整蓝色域明度以确保可读性，在档案设计中可用于方案B的视觉变异。","tags":["反转","蓝底白纹","底片","方案B","视觉冲击"],"relatedIds":[65,62,64],"params":[{"key":"mode","label":"反转模式","type":"select","value":"full"},{"key":"bgColor","label":"反转背景","type":"color","value":"#1a3a6b"},{"key":"fgColor","label":"反转前景","type":"color","value":"#f0eeeb"}],"source":"算法色系"},
  {"id":67,"name":"釉面白","nameEn":"Glaze White","category":"color-systems","subcategory":"基础色","description":"釉面白模拟青花瓷白釉的色温，并非纯白而是带微青暖调的瓷白#f8f6f0。这一色彩是整个设计系统的底色基准，所有其他色彩都叠加于釉面白之上。建议作为页面背景色使用，在档案设计中与暖灰阶的#f0eeeb形成微妙的色温差。","tags":["釉面","瓷白","微青","底色基准","白釉"],"relatedIds":[63,65,72],"params":[{"key":"baseColor","label":"基础色","type":"color","value":"#f8f6f0"},{"key":"warmShift","label":"暖调偏移","type":"number","value":"3"},{"key":"opacity","label":"不透明度","type":"number","value":"100"}],"source":"矿物色系"},
  {"id":68,"name":"窑变紫","nameEn":"Kiln Purple","category":"color-systems","subcategory":"变异色","description":"窑变紫是钴蓝在窑变条件下的意外发色，蓝中带紫，色值约#4a3a6b。窑变是可控与不可控的边界——正如算法中的随机种子。建议作为点缀色使用，面积不超过5%以保持单色约束的基调，在档案设计中可用于高亮或特殊标记。","tags":["窑变","紫色","意外发色","点缀色","边界色"],"relatedIds":[61,69,66],"params":[{"key":"purpleValue","label":"紫色值","type":"color","value":"#4a3a6b"},{"key":"maxArea","label":"最大面积比","type":"number","value":"5"},{"key":"blendMode","label":"混合模式","type":"select","value":"multiply"}],"source":"矿物色系"},
  {"id":69,"name":"青花渐变","nameEn":"Qinghua Gradient","category":"color-systems","subcategory":"渐变系统","description":"青花渐变模拟青花料在釉下的晕散效果，从浓到淡的自然过渡。渐变方向通常从中心向外或从上到下，模拟料水在坯体上的流动。建议使用3-5个色阶的径向或线性渐变，在档案设计中可替代纯色填充以增加深度和有机感。","tags":["渐变","晕散","料水","流动感","有机"],"relatedIds":[61,70,67],"params":[{"key":"direction","label":"渐变方向","type":"select","value":"radial"},{"key":"steps","label":"色阶数","type":"number","value":"4"},{"key":"fromColor","label":"起始色","type":"color","value":"#1a3a6b"}],"source":"传统美学"},
  {"id":70,"name":"墨色五色","nameEn":"Five Ink Tones","category":"color-systems","subcategory":"灰阶系统","description":"墨色五色源自水墨画的「墨分五色」理论：焦、浓、重、淡、清五个墨色层次。在青花瓷中对应料水的浓淡变化，从最深#0d1b3e到最浅#d0d8e0。建议五个色阶等距分布，在档案设计中可替代线性灰阶以增加文化厚度。","tags":["墨分五色","焦浓重淡清","水墨","料水浓淡","文化灰阶"],"relatedIds":[63,64,61],"params":[{"key":"burnt","label":"焦墨","type":"color","value":"#0d1b3e"},{"key":"heavy","label":"重墨","type":"color","value":"#3a4a5a"},{"key":"light","label":"清墨","type":"color","value":"#d0d8e0"}],"source":"传统美学"},
  {"id":71,"name":"矿物色系","nameEn":"Mineral Pigment System","category":"color-systems","subcategory":"色彩来源","description":"矿物色系源自陶瓷颜料的矿物来源：钴矿蓝、铜矿绿、铁矿红、锰矿紫、锑矿黄。每种矿物色都有其特定的发色温度和还原条件，不可随意混搭。建议在单色约束下仅使用钴矿蓝系，在档案设计中可引用矿物名作为色彩命名体系。","tags":["矿物","钴矿","铜矿","发色温度","地质色彩"],"relatedIds":[72,73,61],"params":[{"key":"primaryMineral","label":"主矿物","type":"select","value":"cobalt"},{"key":"firingTemp","label":"烧制温度","type":"number","value":"1280"},{"key":"atmosphere","label":"窑炉气氛","type":"select","value":"reduction"}],"source":"矿物色系"},
  {"id":72,"name":"算法色系","nameEn":"Algorithmic Color System","category":"color-systems","subcategory":"色彩来源","description":"算法色系源自sRGB色域中的数值映射，色彩由算法生成而非矿物发色。从#1a3a6b到#00e5ff的像素映射代表数字屏幕的色域范围。建议与矿物色系形成对照——同一蓝色，两种来源，两种认知体系，在档案设计中可用于方案B的色彩逻辑。","tags":["sRGB","算法生成","像素映射","数字色域","方案B"],"relatedIds":[71,62,64],"params":[{"key":"colorSpace","label":"色彩空间","type":"select","value":"sRGB"},{"key":"rangeStart","label":"范围起点","type":"color","value":"#1a3a6b"},{"key":"rangeEnd","label":"范围终点","type":"color","value":"#00e5ff"}],"source":"算法色系"},
  {"id":73,"name":"蜀锦色","nameEn":"Shu Brocade Color","category":"color-systems","subcategory":"地域色","description":"蜀锦色提取自四川蜀锦的传统配色：朱红、翠绿、金黄、靛蓝四色交织。在单色约束下仅取靛蓝#2a4a7a作为地域暗示色，其余三色以灰阶等效替代。建议靛蓝使用面积不超过10%以保持低频编码，在档案设计中可作为地域标识色。","tags":["蜀锦","四川","地域色","靛蓝","低频编码"],"relatedIds":[74,75,141],"params":[{"key":"indigo","label":"靛蓝值","type":"color","value":"#2a4a7a"},{"key":"maxArea","label":"最大面积比","type":"number","value":"10"},{"key":"encodingLevel","label":"编码等级","type":"select","value":"low"}],"source":"地域色系"},
  {"id":74,"name":"竹青色","nameEn":"Bamboo Green","category":"color-systems","subcategory":"地域色","description":"竹青色提取自新鲜竹叶的色彩#4a7a5a，是成都地域的植被暗示色。在单色约束下以灰阶等效替代，仅在需要显性地域编码时使用。建议透明度控制在2%-5%作为水印色，在档案设计中可作为竹叶水印的着色参考。","tags":["竹青","植被","成都","水印色","等效替代"],"relatedIds":[73,75,7],"params":[{"key":"greenValue","label":"竹青值","type":"color","value":"#4a7a5a"},{"key":"opacity","label":"透明度","type":"number","value":"3"},{"key":"usage","label":"用途","type":"select","value":"watermark"}],"source":"地域色系"},
  {"id":75,"name":"宣纸色","nameEn":"Xuan Paper Color","category":"color-systems","subcategory":"材质色","description":"宣纸色模拟传统宣纸的微黄暖白#f2ede4，是纸质标签和文档背景的基准色。与釉面白#f8f6f0相比，宣纸色更暖更黄，暗示「纸张」而非「瓷面」。建议作为标签背景和文档区域底色，在档案设计中与釉面白形成材质区分。","tags":["宣纸","微黄","暖白","纸质","材质区分"],"relatedIds":[67,76,63],"params":[{"key":"paperColor","label":"纸色值","type":"color","value":"#f2ede4"},{"key":"texture","label":"纹理","type":"select","value":"subtle"},{"key":"aging","label":"做旧程度","type":"number","value":"10"}],"source":"纸质色系"},
  {"id":76,"name":"端石色","nameEn":"Duan Stone Color","category":"color-systems","subcategory":"材质色","description":"端石色提取自端砚的深紫灰色#3a3540，是墨色五色中焦墨的近亲。端石色比纯黑更温润，带紫灰底调，适合作为深色文字和重色区域的色彩。建议作为标题文字色或深色面板背景，在档案设计中可替代纯黑以增加文化质感。","tags":["端砚","紫灰","温润","深色文字","文化质感"],"relatedIds":[75,70,68],"params":[{"key":"stoneColor","label":"石色值","type":"color","value":"#3a3540"},{"key":"purpleShift","label":"紫调偏移","type":"number","value":"5"},{"key":"usage","label":"用途","type":"select","value":"heading"}],"source":"矿物色系"},
  {"id":77,"name":"铜绿色","nameEn":"Patina Green","category":"color-systems","subcategory":"变异色","description":"铜绿色模拟青铜器表面的氧化铜绿#5a7a6a，是时间侵蚀的色彩证据。在单色约束下以灰阶等效替代，仅在需要表达「时间痕迹」时使用。建议作为锈蚀纹理或做旧效果的着色参考，在档案设计中可暗示档案的年代感。","tags":["铜绿","氧化","时间痕迹","做旧","年代感"],"relatedIds":[78,122,76],"params":[{"key":"greenValue","label":"铜绿值","type":"color","value":"#5a7a6a"},{"key":"oxidation","label":"氧化程度","type":"number","value":"50"},{"key":"textureStyle","label":"纹理风格","type":"select","value":"natural"}],"source":"矿物色系"},
  {"id":78,"name":"朱砂红","nameEn":"Cinnabar Red","category":"color-systems","subcategory":"点缀色","description":"朱砂红#b83a2a是印章和批注的传统色彩，在单色约束系统中作为唯一的例外色使用。朱砂红的使用必须极度克制——仅用于印章、警告标记或关键标注。建议面积不超过1%以保持单色纪律，在档案设计中可用于印章红元素或紧急标记。","tags":["朱砂","印章","批注","例外色","极度克制"],"relatedIds":[77,135,79],"params":[{"key":"redValue","label":"朱砂值","type":"color","value":"#b83a2a"},{"key":"maxArea","label":"最大面积比","type":"number","value":"1"},{"key":"usage","label":"用途","type":"select","value":"seal"}],"source":"矿物色系"},
  {"id":79,"name":"藤黄色","nameEn":"Gamboge Yellow","category":"color-systems","subcategory":"点缀色","description":"藤黄色#c8a830提取自藤黄树脂，是传统国画中与墨配合的暖色。在单色约束下以暖灰阶等效替代，仅在需要显性暖色标注时使用。建议作为高亮标记或特殊注释的着色，在档案设计中可标记待办事项或重要参数。","tags":["藤黄","暖色","高亮","标注","国画"],"relatedIds":[78,80,75],"params":[{"key":"yellowValue","label":"藤黄值","type":"color","value":"#c8a830"},{"key":"maxArea","label":"最大面积比","type":"number","value":"2"},{"key":"blendMode","label":"混合模式","type":"select","value":"normal"}],"source":"矿物色系"},
  {"id":80,"name":"靛青色","nameEn":"Indigo Blue","category":"color-systems","subcategory":"蓝色系","description":"靛青色#2a3a6a是植物染料靛蓝的色彩，比钴蓝更沉更暗，带绿底调。靛青是「青出于蓝而胜于蓝」的原始色名，在青花瓷色彩系统中作为钴蓝的深色变体。建议作为深色背景或暗色模式的底色，在档案设计中可替代钴蓝用于夜间视图。","tags":["靛青","靛蓝","植物染","深色变体","青出于蓝"],"relatedIds":[61,62,73],"params":[{"key":"indigoValue","label":"靛青值","type":"color","value":"#2a3a6a"},{"key":"greenShift","label":"绿调偏移","type":"number","value":"5"},{"key":"usage","label":"用途","type":"select","value":"dark-mode-bg"}],"source":"矿物色系"},
  {"id":81,"name":"12栏网格","nameEn":"12-Column Grid","category":"composition","subcategory":"网格系统","description":"12栏网格是离线档案设计的核心构图框架，将画布等分为12列，配合沟槽形成模块化布局。主体区占7栏约60%、信息面板占3栏约25%、工具栏占1栏约8%、沟槽占1栏。建议沟槽宽度16-24px，在档案设计中作为所有元素的定位基准。","tags":["12栏","网格","模块化","定位基准","沟槽"],"relatedIds":[82,41,181],"params":[{"key":"columns","label":"栏数","type":"number","value":"12"},{"key":"gutter","label":"沟槽宽","type":"number","value":"20"},{"key":"margin","label":"边距","type":"number","value":"40"}],"source":"版面设计"},
  {"id":82,"name":"黄金分割","nameEn":"Golden Ratio","category":"composition","subcategory":"比例系统","description":"黄金分割以1:1.618的比例划分空间，在离线档案中用于方案B的非对称构图。主体偏移至黄金分割点，右侧1/3为文字列，创造视觉张力。建议分割线位置取61.8%处，在档案设计中可替代对称网格以增加动态感。","tags":["1.618","非对称","方案B","黄金点","视觉张力"],"relatedIds":[81,83,34],"params":[{"key":"ratio","label":"分割比","type":"number","value":"1.618"},{"key":"orientation","label":"方向","type":"select","value":"horizontal"},{"key":"offset","label":"偏移方向","type":"select","value":"left"}],"source":"版面设计"},
  {"id":83,"name":"三分法","nameEn":"Rule of Thirds","category":"composition","subcategory":"比例系统","description":"三分法将画布在水平和垂直方向各三等分，形成九宫格。四个交叉点是视觉焦点区域，主体应置于交叉点附近而非正中央。建议主体占据2×2格区域，在档案设计中可作为快速构图的简化替代方案。","tags":["九宫格","三分","视觉焦点","交叉点","快速构图"],"relatedIds":[82,81,84],"params":[{"key":"hDivisions","label":"水平等分","type":"number","value":"3"},{"key":"vDivisions","label":"垂直等分","type":"number","value":"3"},{"key":"focusPoint","label":"焦点位置","type":"select","value":"top-left"}],"source":"版面设计"},
  {"id":84,"name":"对称展板","nameEn":"Symmetric Display Panel","category":"composition","subcategory":"构图策略","description":"对称展板是方案A的核心构图策略，所有元素沿中轴左右对称排列。主体居中60%，两侧信息面板镜像对称，创造博物馆展柜般的秩序感。建议中轴偏差不超过2px以保持严格对称，在档案设计中用于方案A的所有页面构图。","tags":["对称","方案A","展板","中轴","博物馆秩序"],"relatedIds":[85,81,86],"params":[{"key":"centerRatio","label":"中心占比","type":"number","value":"60"},{"key":"sideRatio","label":"侧边占比","type":"number","value":"15"},{"key":"axisTolerance","label":"轴偏差","type":"number","value":"2"}],"source":"版面设计"},
  {"id":85,"name":"非对称编辑","nameEn":"Asymmetric Editorial Layout","category":"composition","subcategory":"构图策略","description":"非对称编辑是方案B的核心构图策略，元素沿黄金分割线偏移排列。右侧1/3为文字列，左侧2/3为视觉区，创造杂志编辑般的动态张力。建议文字列宽度固定，视觉区可弹性伸缩，在档案设计中用于方案B的所有页面构图。","tags":["非对称","方案B","编辑版面","黄金偏移","动态张力"],"relatedIds":[84,82,88],"params":[{"key":"textColumnRatio","label":"文字列占比","type":"number","value":"33"},{"key":"visualColumnRatio","label":"视觉区占比","type":"number","value":"67"},{"key":"overlap","label":"区域重叠","type":"number","value":"5"}],"source":"版面设计"},
  {"id":86,"name":"中央聚焦","nameEn":"Center Focus","category":"composition","subcategory":"焦点策略","description":"中央聚焦将最重要的视觉元素置于画布正中央，周围元素向中心聚拢或从中心辐射。这是方案A的默认焦点策略，与对称展板构图配合使用。建议中央元素占据画布40%-60%面积，在档案设计中用于首页或详情页的主体展示。","tags":["中央","聚焦","方案A","辐射","主体展示"],"relatedIds":[84,87,81],"params":[{"key":"focusSize","label":"焦点占比","type":"number","value":"50"},{"key":"surroundStyle","label":"环绕样式","type":"select","value":"converge"},{"key":"margin","label":"焦点边距","type":"number","value":"20"}],"source":"版面设计"},
  {"id":87,"name":"边缘信息","nameEn":"Edge Information","category":"composition","subcategory":"焦点策略","description":"边缘信息将辅助信息置于画布边缘——顶部标题栏、底部状态栏、侧边参数面板。边缘信息不争夺中央焦点，但始终可见作为上下文参考。建议边缘区域宽度不超过画布的15%，在档案设计中可承载导航、元数据和状态信息。","tags":["边缘","辅助","上下文","不争夺焦点","始终可见"],"relatedIds":[86,46,47],"params":[{"key":"edgeWidth","label":"边缘宽度","type":"number","value":"15"},{"key":"position","label":"位置","type":"select","value":"all"},{"key":"bgOpacity","label":"背景透明度","type":"number","value":"90"}],"source":"版面设计"},
  {"id":88,"name":"层叠深度","nameEn":"Layered Depth","category":"composition","subcategory":"空间策略","description":"层叠深度通过纸质层叠和柔和阴影创造前后层次感，暗示物理档案的触感。前景元素投射微弱阴影于后层，层间偏移2-4px以模拟纸张堆叠。建议阴影模糊半径4-8px、偏移2-3px、不透明度10%-20%，在档案设计中用于方案A的深度表达。","tags":["层叠","阴影","纸质","前后层次","触感"],"relatedIds":[89,84,121],"params":[{"key":"layerOffset","label":"层间偏移","type":"number","value":"3"},{"key":"shadowBlur","label":"阴影模糊","type":"number","value":"6"},{"key":"shadowOpacity","label":"阴影透明度","type":"number","value":"15"}],"source":"版面设计"},
  {"id":89,"name":"覆层注释","nameEn":"Overlay Annotation","category":"composition","subcategory":"空间策略","description":"覆层注释将几何图形和文字标注叠加于主体之上，如同建筑图纸上的红线批注。覆层使用半透明填充和虚线边框，不遮挡主体但增加分析感。建议覆层不透明度20%-40%，在档案设计中用于方案B的分析性视觉表达。","tags":["覆层","批注","几何叠加","半透明","分析感"],"relatedIds":[88,85,90],"params":[{"key":"overlayOpacity","label":"覆层透明度","type":"number","value":"30"},{"key":"shapeType","label":"几何形状","type":"select","value":"mixed"},{"key":"borderStyle","label":"边框样式","type":"select","value":"dashed"}],"source":"版面设计"},
  {"id":90,"name":"对角线构图","nameEn":"Diagonal Composition","category":"composition","subcategory":"动态构图","description":"对角线构图沿画布对角线方向组织视觉元素，创造动态感和方向性。元素沿对角线依次排列，形成从一角到对角的视觉流动。建议对角线角度30°-60°以保持可读性，在档案设计中可用于时间线或流程图的布局方向。","tags":["对角线","动态","方向性","视觉流动","时间线"],"relatedIds":[91,85,98],"params":[{"key":"angle","label":"对角角度","type":"number","value":"45"},{"key":"elementSpacing","label":"元素间距","type":"number","value":"40"},{"key":"direction","label":"方向","type":"select","value":"top-left-to-bottom-right"}],"source":"版面设计"},
  {"id":91,"name":"环形构图","nameEn":"Circular Composition","category":"composition","subcategory":"动态构图","description":"环形构图将元素沿圆周排列，中心留空或放置核心元素。环形排列暗示循环、完整和聚焦，与宝相花的放射对称有形式关联。建议元素数4-12个、等距分布，在档案设计中可用于展示关联概念或功能入口的环形导航。","tags":["环形","圆周","循环","聚焦","宝相花关联"],"relatedIds":[90,13,92],"params":[{"key":"elementCount","label":"元素数","type":"number","value":"8"},{"key":"radius","label":"圆周半径","type":"number","value":"150"},{"key":"centerContent","label":"中心内容","type":"select","value":"icon"}],"source":"版面设计"},
  {"id":92,"name":"模块化拼贴","nameEn":"Modular Collage","category":"composition","subcategory":"拼贴策略","description":"模块化拼贴将不同尺寸的内容模块按网格对齐但自由组合，形成类似Pinterest的瀑布流布局。每个模块保持网格对齐但高度可变，模块间以沟槽分隔。建议模块宽度取网格列宽的整数倍，在档案设计中可用于卡片式内容展示。","tags":["模块化","拼贴","瀑布流","网格对齐","卡片"],"relatedIds":[81,93,100],"params":[{"key":"moduleWidth","label":"模块宽","type":"number","value":"3"},{"key":"gutter","label":"沟槽宽","type":"number","value":"16"},{"key":"heightMode","label":"高度模式","type":"select","value":"auto"}],"source":"版面设计"},
  {"id":93,"name":"出血线构图","nameEn":"Bleed Layout","category":"composition","subcategory":"印刷构图","description":"出血线构图将视觉元素延伸至画布边缘，不留边距，模拟印刷品的出血设计。出血构图创造「溢出」的视觉张力，与裁切标记配合使用暗示「画面比所见更大」。建议出血区域3-5mm，在档案设计中可用于全屏背景或沉浸式展示。","tags":["出血","无边距","溢出","印刷","沉浸式"],"relatedIds":[42,81,94],"params":[{"key":"bleedSize","label":"出血尺寸","type":"number","value":"3"},{"key":"cropMarkOffset","label":"裁切标偏移","type":"number","value":"5"},{"key":"edgeElement","label":"边缘元素","type":"select","value":"image"}],"source":"版面设计"},
  {"id":94,"name":"杂志版面","nameEn":"Magazine Layout","category":"composition","subcategory":"印刷构图","description":"杂志版面借鉴编辑设计的排版策略：大标题、多栏文字、跨页图片、拉引语。版面节奏通过字号对比和留白控制，创造阅读的视觉韵律。建议标题字号与正文字号比3:1以上，在档案设计中可用于长文阅读页或专题展示页。","tags":["杂志","编辑设计","大标题","多栏","视觉韵律"],"relatedIds":[93,85,95],"params":[{"key":"titleRatio","label":"标题正文字比","type":"number","value":"3"},{"key":"columnCount","label":"文字栏数","type":"number","value":"2"},{"key":"whitespace","label":"留白比例","type":"number","value":"20"}],"source":"版面设计"},
  {"id":95,"name":"建筑展板","nameEn":"Architecture Panel","category":"composition","subcategory":"专业构图","description":"建筑展板借鉴建筑学的展示方式：正交投影图、剖面图、轴测图并置，配以技术标注和比例尺。展板强调整体的分析性和精确性，每个区域都有明确的信息功能。建议图纸区域占60%、标注区域占25%、标题区域占15%，在档案设计中可用于技术分析页。","tags":["建筑","展板","正交投影","分析性","精确"],"relatedIds":[96,84,49],"params":[{"key":"drawingRatio","label":"图纸占比","type":"number","value":"60"},{"key":"annotationRatio","label":"标注占比","type":"number","value":"25"},{"key":"scaleBar","label":"比例尺","type":"select","value":"1:100"}],"source":"版面设计"},
  {"id":96,"name":"标本标签","nameEn":"Specimen Label","category":"composition","subcategory":"专业构图","description":"标本标签借鉴自然历史博物馆的标本展示方式：中央标本、下方标签、周围测量标记。标签包含学名、采集地、采集日期等达尔文式元数据。建议标签宽度与标本等宽、字号8-10px，在档案设计中可用于纹饰或色彩的标本式展示。","tags":["标本","博物馆","达尔文式","元数据","采集信息"],"relatedIds":[95,44,57],"params":[{"key":"labelWidth","label":"标签宽度","type":"number","value":"200"},{"key":"fontSize","label":"字号","type":"number","value":"9"},{"key":"fields","label":"字段数","type":"number","value":"5"}],"source":"版面设计"},
  {"id":97,"name":"信息图表","nameEn":"Infographic","category":"composition","subcategory":"数据构图","description":"信息图表以可视化方式呈现数据和流程，结合图标、图表和简短文字说明。信息图表的构图逻辑是「引导视线从数据到洞见」，每个视觉元素都服务于信息传达。建议信息密度适中、留白充足，在档案设计中可用于设计参数的可视化说明。","tags":["信息图表","可视化","数据","流程","引导视线"],"relatedIds":[98,56,57],"params":[{"key":"layout","label":"布局","type":"select","value":"vertical"},{"key":"iconStyle","label":"图标风格","type":"select","value":"line"},{"key":"dataDensity","label":"数据密度","type":"select","value":"medium"}],"source":"版面设计"},
  {"id":98,"name":"时间线","nameEn":"Timeline","category":"composition","subcategory":"数据构图","description":"时间线沿水平或垂直轴线按时间顺序排列事件节点，节点间以线段连接。时间线暗示「叙事」和「演进」，适合展示青花瓷的历史发展或设计流程。建议节点间距等比于时间跨度，在档案设计中可用于历史年表或项目进度展示。","tags":["时间线","叙事","演进","节点","年表"],"relatedIds":[97,90,99],"params":[{"key":"direction","label":"方向","type":"select","value":"horizontal"},{"key":"nodeStyle","label":"节点样式","type":"select","value":"dot"},{"key":"spacing","label":"间距模式","type":"select","value":"proportional"}],"source":"版面设计"},
  {"id":99,"name":"流程图","nameEn":"Flowchart","category":"composition","subcategory":"数据构图","description":"流程图以方框和箭头展示步骤和决策的逻辑流程，是技术文档的标准构图方式。流程图的每个节点有明确的输入输出，箭头指示流向。建议节点宽度统一、箭头标注条件，在档案设计中可用于设计流程或参数决策树的可视化。","tags":["流程图","逻辑","方框","箭头","决策树"],"relatedIds":[98,97,100],"params":[{"key":"nodeWidth","label":"节点宽度","type":"number","value":"120"},{"key":"direction","label":"流向","type":"select","value":"top-to-bottom"},{"key":"arrowStyle","label":"箭头样式","type":"select","value":"simple"}],"source":"版面设计"},
  {"id":100,"name":"矩阵排列","nameEn":"Matrix Arrangement","category":"composition","subcategory":"数据构图","description":"矩阵排列将元素按行列等距排列成网格，每个单元格大小相同。矩阵排列暗示「系统化」和「穷举」，适合展示色彩系统、纹饰变体或参数组合。建议行列数取4×5或5×4以填满视口，在档案设计中可用于色彩面板或纹饰目录的展示。","tags":["矩阵","网格","系统化","穷举","等距"],"relatedIds":[81,92,97],"params":[{"key":"columns","label":"列数","type":"number","value":"5"},{"key":"rows","label":"行数","type":"number","value":"4"},{"key":"cellSize","label":"单元格尺寸","type":"number","value":"80"}],"source":"版面设计"},
  {"id":101,"name":"粗体CJK标题","nameEn":"Bold CJK Heading","category":"typography","subcategory":"标题排版","description":"粗体CJK标题使用加粗的中文日韩字体作为页面标题，字重700-900，字号24-48px。标题是视觉层级的最顶层，需与正文形成3:1以上的字号对比。建议使用思源黑体Bold或Noto Sans SC Bold，在档案设计中用于页面主标题和区块标题。","tags":["粗体","CJK","标题","字重700","视觉层级"],"relatedIds":[102,106,107],"params":[{"key":"fontWeight","label":"字重","type":"number","value":"700"},{"key":"fontSize","label":"字号","type":"number","value":"36"},{"key":"fontFamily","label":"字体","type":"select","value":"noto-sans-sc"}],"source":"排版设计"},
  {"id":102,"name":"等宽注释","nameEn":"Monospace Annotation","category":"typography","subcategory":"辅助排版","description":"等宽注释使用等宽字体展示代码、参数值和技术标注。等宽字体的固定字宽确保数值对齐和可读性。建议字号10-12px、行高1.4-1.6，在档案设计中用于参数面板、代码片段和技术标注。","tags":["等宽","注释","代码","参数值","对齐"],"relatedIds":[101,103,108],"params":[{"key":"fontSize","label":"字号","type":"number","value":"11"},{"key":"lineHeight","label":"行高","type":"number","value":"1.5"},{"key":"fontFamily","label":"字体","type":"select","value":"jetbrains-mono"}],"source":"排版设计"},
  {"id":103,"name":"纸条背景","nameEn":"Paper Strip Background","category":"typography","subcategory":"文字容器","description":"纸条背景为文字提供微黄的纸质背景条，模拟贴在页面上的纸条效果。纸条宽度与文字等宽，高度包含上下内边距4-6px。建议背景色#f5f0e8、边框1px solid #d0ccc5，在档案设计中可用于标签、注释或临时标注的文字容器。","tags":["纸条","微黄","贴纸","文字容器","标注"],"relatedIds":[104,44,75],"params":[{"key":"bgColor","label":"背景色","type":"color","value":"#f5f0e8"},{"key":"padding","label":"内边距","type":"number","value":"5"},{"key":"borderWidth","label":"边框宽","type":"number","value":"1"}],"source":"排版设计"},
  {"id":104,"name":"博物馆标签","nameEn":"Museum Label","category":"typography","subcategory":"文字容器","description":"博物馆标签模拟博物馆展品说明牌的排版格式：顶部编号行、中间名称行、底部说明行。三行信息形成严格的层级关系。建议编号8px、名称14px、说明10px，在档案设计中可用于任何视觉元素的标注。","tags":["博物馆","展品标签","编号","层级","三行格式"],"relatedIds":[103,44,96],"params":[{"key":"idSize","label":"编号字号","type":"number","value":"8"},{"key":"nameSize","label":"名称字号","type":"number","value":"14"},{"key":"descSize","label":"说明字号","type":"number","value":"10"}],"source":"排版设计"},
  {"id":105,"name":"拉引语","nameEn":"Pull Quote","category":"typography","subcategory":"强调排版","description":"拉引语将重要引文从正文中提取并以大号字体独立展示，通常配以引号装饰和来源标注。拉引语打破正文节奏，创造视觉停顿和重点强调。建议字号为正文的2-3倍、左右缩进20%，在档案设计中可用于设计哲学或关键理念的突出展示。","tags":["引语","提取","大号","引号","视觉停顿"],"relatedIds":[101,106,115],"params":[{"key":"fontSize","label":"字号","type":"number","value":"24"},{"key":"indent","label":"缩进","type":"number","value":"20"},{"key":"quoteMark","label":"引号样式","type":"select","value":"curly"}],"source":"排版设计"},
  {"id":106,"name":"编号标注","nameEn":"Numbered Annotation","category":"typography","subcategory":"标注排版","description":"编号标注以带圈数字或序号标记视觉元素，配合引线指向目标位置。编号标注建立元素与说明文字之间的对应关系。建议带圈数字直径12-16px、引线0.5px细线，在档案设计中可用于分解图或步骤说明。","tags":["编号","带圈数字","引线","对应关系","分解图"],"relatedIds":[107,102,49],"params":[{"key":"numberStyle","label":"编号样式","type":"select","value":"circled"},{"key":"numberSize","label":"编号尺寸","type":"number","value":"14"},{"key":"leaderLine","label":"引线样式","type":"select","value":"thin"}],"source":"排版设计"},
  {"id":107,"name":"元数据字段","nameEn":"Metadata Field","category":"typography","subcategory":"标注排版","description":"元数据字段以「字段名: 值」的格式展示结构化信息，如「产地: 景德镇」「年代: 明永乐」。字段名使用等宽小字、值使用常规字体，冒号对齐。建议字段名字号8-9px、值字号10-11px，在档案设计中可用于信息面板的参数展示。","tags":["元数据","字段名","键值对","等宽","冒号对齐"],"relatedIds":[106,108,44],"params":[{"key":"labelSize","label":"字段名字号","type":"number","value":"9"},{"key":"valueSize","label":"值字号","type":"number","value":"11"},{"key":"alignment","label":"对齐方式","type":"select","value":"colon"}],"source":"排版设计"},
  {"id":108,"name":"分类代码","nameEn":"Classification Code","category":"typography","subcategory":"标注排版","description":"分类代码以简短的字母数字组合标识类别，如「QH-001」「FR-012」。代码使用等宽大写字母，暗示档案系统的编号逻辑。建议代码格式「类别缩写-序号」、字号8-10px，在档案设计中可用于纹饰、分形、色彩等分类的编号标识。","tags":["分类","代码","编号","等宽大写","档案逻辑"],"relatedIds":[107,109,102],"params":[{"key":"codeFormat","label":"代码格式","type":"text","value":"XX-000"},{"key":"fontSize","label":"字号","type":"number","value":"9"},{"key":"letterSpacing","label":"字距","type":"number","value":"1"}],"source":"排版设计"},
  {"id":109,"name":"文件引用","nameEn":"File Reference","category":"typography","subcategory":"标注排版","description":"文件引用以路径格式标识资源位置，如「/assets/patterns/lotus.svg」。路径使用等宽字体、正斜杠分隔，暗示文件系统的层级结构。建议字号9-10px、路径颜色使用钴蓝辅色，在档案设计中可用于资源定位和技术引用。","tags":["文件路径","等宽","斜杠分隔","资源定位","层级结构"],"relatedIds":[108,102,110],"params":[{"key":"fontSize","label":"字号","type":"number","value":"10"},{"key":"pathColor","label":"路径色","type":"color","value":"#4a7ab5"},{"key":"format","label":"格式","type":"select","value":"unix"}],"source":"排版设计"},
  {"id":110,"name":"中英混排","nameEn":"CJK-Latin Mixed Typesetting","category":"typography","subcategory":"混排策略","description":"中英混排处理中文与拉丁字母在同一行内的共存问题，需调整字距、基线和字号以保持视觉平衡。中文与英文之间建议插入1/4em间距，英文字号比中文小1-2px以匹配视觉大小。在档案设计中广泛用于标题、标签和元数据的双语展示。","tags":["中英","混排","字距","基线","双语"],"relatedIds":[101,111,112],"params":[{"key":"interSpacing","label":"中英间距","type":"number","value":"0.25"},{"key":"latinScale","label":"拉丁缩放","type":"number","value":"0.92"},{"key":"baselineAdjust","label":"基线调整","type":"number","value":"1"}],"source":"排版设计"},
  {"id":111,"name":"扩展字距","nameEn":"Extended Tracking","category":"typography","subcategory":"间距策略","description":"扩展字距增大字母和汉字之间的间距，创造疏朗、高端的排版效果。扩展字距常用于大标题和标签，暗示「从容」和「精确」。建议CJK字距+0.05-0.1em、拉丁字距+50-100，在档案设计中可用于区块标题和分类标签。","tags":["字距","扩展","疏朗","高端","从容"],"relatedIds":[112,101,108],"params":[{"key":"cjkTracking","label":"CJK字距","type":"number","value":"0.08"},{"key":"latinTracking","label":"拉丁字距","type":"number","value":"80"},{"key":"appliedTo","label":"应用范围","type":"select","value":"headings"}],"source":"排版设计"},
  {"id":112,"name":"浓缩字体","nameEn":"Condensed Font","category":"typography","subcategory":"字体变体","description":"浓缩字体使用窄体字族在有限空间内容纳更多文字，字宽约为常规字体的80%-85%。浓缩字体适合信息密集的区域如数据表格和参数面板。建议字号比常规大1-2px以补偿窄体的可读性损失，在档案设计中可用于表格表头和侧边栏标签。","tags":["浓缩","窄体","信息密集","表格","侧边栏"],"relatedIds":[111,113,57],"params":[{"key":"widthRatio","label":"宽度比","type":"number","value":"0.82"},{"key":"fontSize","label":"字号","type":"number","value":"11"},{"key":"fontFamily","label":"字体","type":"select","value":"noto-sans-sc-condensed"}],"source":"排版设计"},
  {"id":113,"name":"超大地层字","nameEn":"Oversized Display Type","category":"typography","subcategory":"字体变体","description":"超大地层字使用极大字号的文字作为背景装饰层，不承担阅读功能而承担视觉氛围功能。大字通常使用极低不透明度或极浅色值。建议字号120px以上、不透明度10%以下，在档案设计中可作为页面的氛围层文字。","tags":["超大字","背景层","氛围","低不透明度","装饰性"],"relatedIds":[101,114,88],"params":[{"key":"fontSize","label":"字号","type":"number","value":"120"},{"key":"opacity","label":"不透明度","type":"number","value":"8"},{"key":"zIndex","label":"层级","type":"number","value":"0"}],"source":"排版设计"},
  {"id":114,"name":"辅助文字","nameEn":"Supporting Text","category":"typography","subcategory":"字体变体","description":"辅助文字是视觉层级最底层的文字，字号8-10px、颜色使用灰阶中浅色、字重300-400。辅助文字不争夺注意力但提供必要的上下文信息。建议与主文字形成2:1以上的字号对比，在档案设计中可用于脚注、来源说明和技术参数。","tags":["辅助","小字","底层","脚注","上下文"],"relatedIds":[113,119,102],"params":[{"key":"fontSize","label":"字号","type":"number","value":"9"},{"key":"fontWeight","label":"字重","type":"number","value":"300"},{"key":"color","label":"颜色","type":"color","value":"#8a8680"}],"source":"排版设计"},
  {"id":115,"name":"标签胶囊","nameEn":"Tag Capsule","category":"typography","subcategory":"文字容器","description":"标签胶囊以圆角矩形包裹标签文字，形成胶囊状的标签元素。胶囊内文字字号8-10px、上下内边距2-4px、左右内边距6-10px、圆角半径等于高度的一半。建议胶囊背景使用浅灰或浅蓝，在档案设计中可用于分类标签和状态标记。","tags":["胶囊","标签","圆角","分类","状态"],"relatedIds":[116,103,108],"params":[{"key":"fontSize","label":"字号","type":"number","value":"9"},{"key":"paddingH","label":"水平内边距","type":"number","value":"8"},{"key":"paddingV","label":"垂直内边距","type":"number","value":"3"}],"source":"排版设计"},
  {"id":116,"name":"参数高亮","nameEn":"Parameter Highlight","category":"typography","subcategory":"强调排版","description":"参数高亮以背景色块或下划线标记参数名称和数值，使其从正文或代码中视觉突出。高亮色使用钴蓝辅色#4a7ab5的浅色变体。建议高亮背景不透明度10%-20%、圆角2px，在档案设计中可用于参数面板中的关键数值标注。","tags":["参数","高亮","色块","下划线","数值标注"],"relatedIds":[115,117,107],"params":[{"key":"highlightColor","label":"高亮色","type":"color","value":"#4a7ab5"},{"key":"bgOpacity","label":"背景透明度","type":"number","value":"15"},{"key":"borderRadius","label":"圆角","type":"number","value":"2"}],"source":"排版设计"},
  {"id":117,"name":"色块标注","nameEn":"Color Block Annotation","category":"typography","subcategory":"强调排版","description":"色块标注在文字左侧或顶部添加小色块作为视觉标记，色块颜色对应标注类别。色块宽度3-4px、高度与文字行高一致。建议色块颜色从色彩系统中取值，在档案设计中可用于分类标注或层级标记。","tags":["色块","侧标","分类","视觉标记","层级"],"relatedIds":[116,115,107],"params":[{"key":"blockWidth","label":"色块宽","type":"number","value":"3"},{"key":"blockColor","label":"色块色","type":"color","value":"#1a3a6b"},{"key":"position","label":"位置","type":"select","value":"left"}],"source":"排版设计"},
  {"id":118,"name":"行号标记","nameEn":"Line Number Marker","category":"typography","subcategory":"标注排版","description":"行号标记在代码块或数据表的左侧显示行号，使用等宽字体、浅灰色、右对齐。行号暗示「可引用」和「可定位」的精确性。建议行号字号比代码小1-2px、颜色使用灰阶浅色，在档案设计中可用于代码展示和数据表格的行定位。","tags":["行号","等宽","右对齐","可引用","精确定位"],"relatedIds":[102,119,57],"params":[{"key":"fontSize","label":"字号","type":"number","value":"9"},{"key":"color","label":"颜色","type":"color","value":"#c0bbb5"},{"key":"gutterWidth","label":"行号栏宽","type":"number","value":"30"}],"source":"排版设计"},
  {"id":119,"name":"脚注引用","nameEn":"Footnote Reference","category":"typography","subcategory":"标注排版","description":"脚注引用以上标数字标记正文中的引用点，页面底部列出对应的脚注内容。脚注引用暗示「有出处」和「可验证」的学术态度。建议上标字号6-7px、脚注字号8-9px，在档案设计中可用于来源说明和参考文献的标记。","tags":["脚注","上标","引用","出处","学术"],"relatedIds":[118,114,120],"params":[{"key":"superscriptSize","label":"上标字号","type":"number","value":"7"},{"key":"footnoteSize","label":"脚注字号","type":"number","value":"8"},{"key":"separatorStyle","label":"分隔线","type":"select","value":"short-line"}],"source":"排版设计"},
  {"id":120,"name":"图注编号","nameEn":"Figure Caption Number","category":"typography","subcategory":"标注排版","description":"图注编号以「图1」「Fig.1」格式为图片和图表编号，编号使用等宽或浓缩字体。图注编号暗示「有序展示」和「可引用」的文档结构。建议编号字号9-10px、置于图片下方居左，在档案设计中可用于所有视觉元素的编号和说明。","tags":["图注","编号","Fig","有序","可引用"],"relatedIds":[119,106,108],"params":[{"key":"format","label":"格式","type":"select","value":"fig-number"},{"key":"fontSize","label":"字号","type":"number","value":"9"},{"key":"position","label":"位置","type":"select","value":"below-left"}],"source":"排版设计"},
  {"id":121,"name":"角括号","nameEn":"Corner Brackets Decorative","category":"decorative","subcategory":"框架装饰","description":"角括号装饰由四个L形角标框定内容区域，是离线档案美学的标志性元素。角括号不闭合四边只标记四角，暗示「被框选但未封闭」的状态。建议括号线宽1px、内缩8-12px，在档案设计中可框定任何内容区块以增加档案感。","tags":["角标","L形","框选","未封闭","标志性"],"relatedIds":[122,41,45],"params":[{"key":"bracketSize","label":"括号尺寸","type":"number","value":"12"},{"key":"inset","label":"内缩距离","type":"number","value":"8"},{"key":"lineWidth","label":"线宽","type":"number","value":"1"}],"source":"UI设计模式"},
  {"id":122,"name":"圆点群","nameEn":"Dot Cluster","category":"decorative","subcategory":"点状装饰","description":"圆点群由大小不一的圆点按一定规律排列组成，可疏可密、可大可小。圆点群在离线档案美学中暗示「标记」「定位」和「节奏」。建议圆点直径2-6px、间距4-8px，在档案设计中可作为分隔区域的装饰或背景点缀。","tags":["圆点","标记","节奏","疏密","点缀"],"relatedIds":[121,123,55],"params":[{"key":"dotSize","label":"圆点直径","type":"number","value":"4"},{"key":"spacing","label":"间距","type":"number","value":"6"},{"key":"arrangement","label":"排列","type":"select","value":"grid"}],"source":"UI设计模式"},
  {"id":123,"name":"细边框","nameEn":"Thin Border","category":"decorative","subcategory":"线状装饰","description":"细边框以0.5-1px的细线围合内容区域，是离线档案美学中最克制的装饰方式。细边框暗示「有边界」但不强调边界，保持内容的开放感。建议线宽0.5px、颜色使用灰阶中浅色，在档案设计中可用于卡片、面板和图片的边框。","tags":["细线","边框","克制","有边界","开放感"],"relatedIds":[121,124,3],"params":[{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"},{"key":"color","label":"颜色","type":"color","value":"#d0ccc5"},{"key":"borderRadius","label":"圆角","type":"number","value":"0"}],"source":"UI设计模式"},
  {"id":124,"name":"虚线","nameEn":"Dashed Line","category":"decorative","subcategory":"线状装饰","description":"虚线以间断的线段组成，在离线档案美学中暗示「暂定」「待定」或「可裁切」的状态。虚线比实线更轻更弱，不争夺视觉注意力。建议线段长度4-6px、间隔2-4px、线宽0.5px，在档案设计中可用于分隔线、折叠指示或裁切引导。","tags":["虚线","暂定","间断","轻量","裁切"],"relatedIds":[123,125,42],"params":[{"key":"dashLength","label":"线段长度","type":"number","value":"4"},{"key":"gapLength","label":"间隔长度","type":"number","value":"3"},{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"}],"source":"UI设计模式"},
  {"id":125,"name":"十字准星","nameEn":"Crosshair","category":"decorative","subcategory":"标记装饰","description":"十字准星由两条正交的细线交叉组成，中心可加小圆点。十字准星暗示「精确瞄准」和「对焦」，是技术图纸和测量仪器的标志性元素。建议线长12-20px、线宽0.5px，在档案设计中可标记焦点位置或对齐参考点。","tags":["十字","准星","瞄准","对焦","精确"],"relatedIds":[121,43,49],"params":[{"key":"lineLength","label":"线长","type":"number","value":"16"},{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"},{"key":"centerDot","label":"中心点","type":"select","value":"yes"}],"source":"UI设计模式"},
  {"id":126,"name":"引导线","nameEn":"Leader Line","category":"decorative","subcategory":"线状装饰","description":"引导线从标注文字指向目标位置的细线，通常带有折角或小圆点端点。引导线建立文字与图形之间的视觉关联，是技术标注的标准元素。建议线宽0.5px、折角45°，在档案设计中可用于编号标注和参数指向。","tags":["引导","指向","折角","关联","标注线"],"relatedIds":[124,106,49],"params":[{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"},{"key":"angle","label":"折角","type":"number","value":"45"},{"key":"endStyle","label":"端点样式","type":"select","value":"dot"}],"source":"UI设计模式"},
  {"id":127,"name":"坐标轴","nameEn":"Coordinate Axis","category":"decorative","subcategory":"框架装饰","description":"坐标轴由水平X轴和垂直Y轴组成，轴端带箭头，轴上可有刻度标记。坐标轴暗示「量化」和「定位」的数学思维，是数据可视化的基础框架。建议轴线0.5px、刻度2px，在档案设计中可用于图表框架或参数空间的坐标参考。","tags":["坐标","X轴Y轴","量化","刻度","数学"],"relatedIds":[121,49,56],"params":[{"key":"lineWidth","label":"轴线宽","type":"number","value":"0.5"},{"key":"tickLength","label":"刻度长","type":"number","value":"2"},{"key":"arrowStyle","label":"箭头样式","type":"select","value":"simple"}],"source":"UI设计模式"},
  {"id":128,"name":"带圈数字","nameEn":"Circled Number","category":"decorative","subcategory":"标记装饰","description":"带圈数字将数字置于圆形之中，形成独立的标记符号。带圈数字在离线档案美学中暗示「有序步骤」和「可引用编号」。建议圆径14-18px、数字居中、线宽0.5px，在档案设计中可用于步骤编号、分解图标记或列表序号。","tags":["带圈","数字","步骤","编号","有序"],"relatedIds":[125,106,122],"params":[{"key":"circleSize","label":"圆径","type":"number","value":"16"},{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"},{"key":"fillStyle","label":"填充样式","type":"select","value":"outline"}],"source":"UI设计模式"},
  {"id":129,"name":"箭头端点","nameEn":"Arrow Endpoint","category":"decorative","subcategory":"标记装饰","description":"箭头端点是线段末端的三角形标记，指示方向和流向。箭头在离线档案美学中暗示「指向」「流动」和「因果关系」。建议箭头长度6-10px、宽度3-5px，在档案设计中可用于流程图、引导线和方向指示。","tags":["箭头","方向","流向","指向","三角"],"relatedIds":[126,127,99],"params":[{"key":"arrowLength","label":"箭头长","type":"number","value":"8"},{"key":"arrowWidth","label":"箭头宽","type":"number","value":"4"},{"key":"style","label":"样式","type":"select","value":"filled"}],"source":"UI设计模式"},
  {"id":130,"name":"波浪线","nameEn":"Wavy Line","category":"decorative","subcategory":"线状装饰","description":"波浪线以正弦曲线形态呈现，在离线档案美学中暗示「水面」「流动」和「柔和边界」。波浪线与海水江崖纹有形式关联，是直线装饰的有机替代。建议波长8-16px、振幅2-4px，在档案设计中可用于分隔线或装饰边框。","tags":["波浪","正弦","水面","流动","柔和"],"relatedIds":[124,2,6],"params":[{"key":"wavelength","label":"波长","type":"number","value":"12"},{"key":"amplitude","label":"振幅","type":"number","value":"3"},{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"}],"source":"UI设计模式"},
  {"id":131,"name":"锯齿线","nameEn":"Zigzag Line","category":"decorative","subcategory":"线状装饰","description":"锯齿线由连续的尖角折线组成，在离线档案美学中暗示「警示」「撕裂」和「能量」。锯齿线比波浪线更具攻击性，适合表达紧急或断裂的状态。建议锯齿角度60°-90°、线宽0.5px，在档案设计中可用于警示边框或撕裂效果。","tags":["锯齿","尖角","警示","撕裂","能量"],"relatedIds":[130,124,125],"params":[{"key":"angle","label":"锯齿角度","type":"number","value":"75"},{"key":"segmentLength","label":"段长","type":"number","value":"6"},{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"}],"source":"UI设计模式"},
  {"id":132,"name":"点划线","nameEn":"Dot-Dash Line","category":"decorative","subcategory":"线状装饰","description":"点划线由短划线和点交替组成，是工程制图中表示中心线或假想轮廓线的标准线型。点划线暗示「参考」和「假想」的工程思维。建议划线长度8-12px、点间距2-3px，在档案设计中可用于中心线、对称轴或辅助参考线。","tags":["点划","中心线","工程制图","参考","假想"],"relatedIds":[124,123,127],"params":[{"key":"dashLength","label":"划线长","type":"number","value":"10"},{"key":"dotSpacing","label":"点间距","type":"number","value":"3"},{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"}],"source":"UI设计模式"},
  {"id":133,"name":"双线框","nameEn":"Double Line Frame","category":"decorative","subcategory":"框架装饰","description":"双线框由两条平行细线围合内容区域，两线间距2-4px。双线框比单线框更正式、更强调边界，暗示「重要内容」和「正式框定」。建议外线0.5px、内线0.5px、间距3px，在档案设计中可用于重要卡片或核心区域的边框。","tags":["双线","平行","正式","框定","重要"],"relatedIds":[121,123,134],"params":[{"key":"outerWidth","label":"外线宽","type":"number","value":"0.5"},{"key":"innerWidth","label":"内线宽","type":"number","value":"0.5"},{"key":"gap","label":"线间距","type":"number","value":"3"}],"source":"UI设计模式"},
  {"id":134,"name":"阴影框","nameEn":"Shadow Frame","category":"decorative","subcategory":"框架装饰","description":"阴影框通过偏移投影创造浮起效果，模拟纸张从桌面微微抬起的状态。阴影框暗示「物理存在」和「可拾取」的触感暗示。建议阴影偏移3-5px、模糊4-8px、不透明度10%-15%，在档案设计中可用于卡片和面板的立体感表达。","tags":["阴影","浮起","物理","触感","立体"],"relatedIds":[133,88,121],"params":[{"key":"offsetX","label":"X偏移","type":"number","value":"3"},{"key":"offsetY","label":"Y偏移","type":"number","value":"3"},{"key":"blur","label":"模糊","type":"number","value":"6"},{"key":"opacity","label":"透明度","type":"number","value":"12"}],"source":"UI设计模式"},
  {"id":135,"name":"毛边纸","nameEn":"Rough Edge Paper","category":"decorative","subcategory":"材质装饰","description":"毛边纸模拟手工撕纸的不规则边缘效果，边缘呈锯齿状或纤维状。毛边纸暗示「手工制作」和「非工业化」的质感，与裁切标记的精确性形成对比。建议边缘偏移2-5px，在档案设计中可用于纸质标签或文档区域的边缘处理。","tags":["毛边","手工","撕纸","非工业","纤维状"],"relatedIds":[125,134,44],"params":[{"key":"roughness","label":"粗糙度","type":"number","value":"40"},{"key":"edgeWidth","label":"边缘宽度","type":"number","value":"3"},{"key":"fiberDensity","label":"纤维密度","type":"number","value":"5"}],"source":"纸质纹理"},
  {"id":136,"name":"咖啡环","nameEn":"Coffee Ring Stain","category":"decorative","subcategory":"痕迹装饰","description":"咖啡环模拟咖啡杯在纸面上留下的环形水渍痕迹，是方案B「桌面式」空间逻辑的标志性元素。咖啡环暗示「正在使用」和「人的痕迹」，打破设计的完美感。建议环径30-60px、不透明度5%-10%，在档案设计中可置于角落作为生活痕迹装饰。","tags":["咖啡环","水渍","人的痕迹","生活感","桌面"],"relatedIds":[135,137,89],"params":[{"key":"ringDiameter","label":"环径","type":"number","value":"45"},{"key":"opacity","label":"不透明度","type":"number","value":"8"},{"key":"position","label":"位置","type":"select","value":"corner"}],"source":"痕迹纹理"},
  {"id":137,"name":"折角","nameEn":"Folded Corner","category":"decorative","subcategory":"痕迹装饰","description":"折角模拟纸张角落被折叠的效果，三角形的折角区域颜色略深于周围。折角暗示「被翻阅」和「有物理存在」，是纸质文档的标志性痕迹。建议折角尺寸12-20px，在档案设计中可用于卡片或文档区域的角落装饰。","tags":["折角","翻阅","纸质","物理痕迹","三角"],"relatedIds":[135,136,134],"params":[{"key":"cornerSize","label":"折角尺寸","type":"number","value":"16"},{"key":"position","label":"位置","type":"select","value":"top-right"},{"key":"shadowDepth","label":"阴影深度","type":"number","value":"2"}],"source":"纸质纹理"},
  {"id":138,"name":"装订孔","nameEn":"Binding Hole","category":"decorative","subcategory":"痕迹装饰","description":"装订孔模拟纸张左侧的圆形打孔，是活页文件夹的标准特征。装订孔暗示「可归档」和「有组织系统」的档案属性。建议孔径4-6px、间距20-30px、距边缘8-12px，在档案设计中可置于页面左侧作为档案系统暗示。","tags":["装订孔","活页","归档","组织系统","圆形"],"relatedIds":[137,135,44],"params":[{"key":"holeSize","label":"孔径","type":"number","value":"5"},{"key":"spacing","label":"孔间距","type":"number","value":"25"},{"key":"margin","label":"距边缘","type":"number","value":"10"}],"source":"纸质纹理"},
  {"id":139,"name":"水印","nameEn":"Watermark","category":"decorative","subcategory":"痕迹装饰","description":"水印以极低不透明度的图案或文字叠加于内容之上，不影响阅读但传递隐含信息。水印暗示「版权」「机密」或「身份标识」。建议不透明度2%-5%、置于内容层之下，在档案设计中可用于品牌标识或地域暗示如竹叶水印。","tags":["水印","低不透明度","隐含信息","品牌","标识"],"relatedIds":[136,137,7],"params":[{"key":"opacity","label":"不透明度","type":"number","value":"3"},{"key":"pattern","label":"图案","type":"select","value":"bamboo-leaf"},{"key":"position","label":"位置","type":"select","value":"center"}],"source":"纸质纹理"},
  {"id":140,"name":"贴纸","nameEn":"Sticker","category":"decorative","subcategory":"材质装饰","description":"贴纸模拟可撕贴的标签纸效果，带有微弱的阴影和略微倾斜的角度。贴纸暗示「临时附加」和「可移动」的非固定信息。建议倾斜角度-3°到3°、阴影偏移1-2px，在档案设计中可用于临时标注、状态标签或便签式信息。","tags":["贴纸","临时","可移动","倾斜","便签"],"relatedIds":[135,137,103],"params":[{"key":"rotation","label":"旋转角度","type":"number","value":"-2"},{"key":"shadowBlur","label":"阴影模糊","type":"number","value":"3"},{"key":"bgColor","label":"背景色","type":"color","value":"#f5f0e8"}],"source":"UI设计模式"},
  {"id":141,"name":"冰裂纹","nameEn":"Ice Crack Texture","category":"textures","subcategory":"瓷器纹理","description":"冰裂纹是瓷器釉面的开片纹理，由釉与胎的膨胀系数差异导致。裂纹呈不规则多边形网络，线宽0.5-1px，从中心向边缘辐射。建议裂纹密度6-12条/100px，在档案设计中可作为背景纹理或装饰性覆层，与Voronoi图有形式关联。","tags":["冰裂","开片","多边形","辐射","Voronoi关联"],"relatedIds":[18,35,121],"params":[{"key":"density","label":"裂纹密度","type":"number","value":"8"},{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"},{"key":"color","label":"裂纹色","type":"color","value":"#8a9aaa"}],"source":"瓷器纹理"},
  {"id":142,"name":"釉面光泽","nameEn":"Glaze Gloss Texture","category":"textures","subcategory":"瓷器纹理","description":"釉面光泽模拟瓷器表面玻璃质釉层的光反射效果，表现为柔和的高光渐变和微弱的镜面反射。光泽区域通常位于器物凸起处，呈椭圆形亮斑。建议高光不透明度15%-30%、模糊半径20-40px，在档案设计中可叠加于任何元素上增加瓷质感。","tags":["釉面","光泽","高光","镜面","瓷质感"],"relatedIds":[141,143,122],"params":[{"key":"highlightOpacity","label":"高光透明度","type":"number","value":"20"},{"key":"blurRadius","label":"模糊半径","type":"number","value":"30"},{"key":"shape","label":"高光形状","type":"select","value":"ellipse"}],"source":"瓷器纹理"},
  {"id":143,"name":"纤维纹理","nameEn":"Fiber Texture","category":"textures","subcategory":"纸张纹理","description":"纤维纹理模拟纸张内部的植物纤维走向，表现为细微的定向线条和颗粒。纤维方向通常一致，偶尔交叉，密度低而不均匀。建议纤维线宽0.3-0.5px、不透明度3%-8%，在档案设计中可作为纸质标签和文档区域的微纹理覆层。","tags":["纤维","纸张","定向","微纹理","低密度"],"relatedIds":[144,145,75],"params":[{"key":"fiberWidth","label":"纤维线宽","type":"number","value":"0.4"},{"key":"opacity","label":"不透明度","type":"number","value":"5"},{"key":"direction","label":"纤维方向","type":"number","value":"0"}],"source":"纸质纹理"},
  {"id":144,"name":"噪点覆层","nameEn":"Noise Overlay Texture","category":"textures","subcategory":"数字纹理","description":"噪点覆层在视觉元素上叠加均匀的随机噪点，模拟印刷品的颗粒感或屏幕的像素噪声。噪点增加「物质感」和「非完美」的触觉暗示。建议噪点强度3%-8%、颗粒大小1px，在档案设计中可全局叠加以统一所有元素的质感基调。","tags":["噪点","颗粒感","物质感","非完美","全局覆层"],"relatedIds":[143,37,145],"params":[{"key":"intensity","label":"强度","type":"number","value":"5"},{"key":"grainSize","label":"颗粒大小","type":"number","value":"1"},{"key":"blendMode","label":"混合模式","type":"select","value":"multiply"}],"source":"数字纹理"},
  {"id":145,"name":"毛边","nameEn":"Deckle Edge Texture","category":"textures","subcategory":"纸张纹理","description":"毛边模拟手工纸边缘的不规则撕裂效果，边缘呈波浪形而非直线。毛边暗示「手工制作」和「非工业化」的质感。建议边缘偏移量1-3px、频率中等，在档案设计中可用于纸质标签、文档区域或整个画布的边缘处理。","tags":["毛边","手工纸","撕裂","非工业","波浪边缘"],"relatedIds":[143,146,75],"params":[{"key":"offset","label":"偏移量","type":"number","value":"2"},{"key":"frequency","label":"频率","type":"number","value":"5"},{"key":"irregularity","label":"不规则度","type":"number","value":"30"}],"source":"纸质纹理"},
  {"id":146,"name":"deckle边缘","nameEn":"Deckle Edge Fine Texture","category":"textures","subcategory":"纸张纹理","description":"deckle边缘是手工纸在纸模上自然形成的精细毛边，比普通毛边更细腻、更不规则。deckle边缘保留纸浆凝固的有机痕迹。建议偏移量0.5-1.5px以保持精细感，在档案设计中可用于高端纸质元素的边缘处理。","tags":["deckle","精细毛边","纸浆","有机","含蓄"],"relatedIds":[145,143,147],"params":[{"key":"offset","label":"偏移量","type":"number","value":"1"},{"key":"detail","label":"细节度","type":"number","value":"80"},{"key":"softness","label":"柔和度","type":"number","value":"60"}],"source":"纸质纹理"},
  {"id":147,"name":"纸纤维","nameEn":"Paper Fiber Visible Texture","category":"textures","subcategory":"纸张纹理","description":"纸纤维是肉眼可见的纸张内部纤维束，比纤维纹理更粗更明显。纤维束呈淡黄色或灰白色，随机分布在纸面上。建议纤维束宽度1-3px、长度10-30px、不透明度5%-10%，在档案设计中可用于做旧纸张或古文档的质感表现。","tags":["纤维束","可见","做旧","古文档","淡黄"],"relatedIds":[143,145,148],"params":[{"key":"fiberWidth","label":"纤维宽","type":"number","value":"2"},{"key":"fiberLength","label":"纤维长","type":"number","value":"20"},{"key":"color","label":"纤维色","type":"color","value":"#d8d0c0"}],"source":"纸质纹理"},
  {"id":148,"name":"丝织纹","nameEn":"Silk Weave Texture","category":"textures","subcategory":"织物纹理","description":"丝织纹模拟丝绸的经纬交织纹理，表现为规则的斜纹或缎纹图案。丝织纹与蜀锦织纹有直接关联，是地域编码的纹理载体。建议纹路间距0.5-1px、不透明度3%-5%，在档案设计中可作为覆层纹理暗示织物质感。","tags":["丝绸","经纬","斜纹","蜀锦关联","地域编码"],"relatedIds":[149,73,128],"params":[{"key":"weaveType","label":"织纹类型","type":"select","value":"twill"},{"key":"spacing","label":"纹路间距","type":"number","value":"0.8"},{"key":"opacity","label":"不透明度","type":"number","value":"4"}],"source":"织物纹理"},
  {"id":149,"name":"竹纹","nameEn":"Bamboo Grain Texture","category":"textures","subcategory":"自然纹理","description":"竹纹模拟竹材表面的纵向纤维纹理，表现为平行的细线条和竹节横纹。竹纹是成都地域的植被暗示，与竹叶纹形成纹理-图形的互补。建议纵向线间距1-2px、竹节间距30-50px，在档案设计中可作为侧边栏或分隔线的纹理覆层。","tags":["竹纹","纵向纤维","竹节","地域暗示","植被"],"relatedIds":[150,7,74],"params":[{"key":"grainSpacing","label":"纹理间距","type":"number","value":"1.5"},{"key":"nodeSpacing","label":"竹节间距","type":"number","value":"40"},{"key":"opacity","label":"不透明度","type":"number","value":"5"}],"source":"自然纹理"},
  {"id":150,"name":"石纹","nameEn":"Stone Texture","category":"textures","subcategory":"自然纹理","description":"石纹模拟石材表面的天然纹理，包括大理石的流动纹、端砚的细腻颗粒和砂岩的层理。石纹与端石色有直接关联，是文化质感的纹理载体。建议纹理方向与元素长边平行，在档案设计中可用于标题背景或深色区域的质感表现。","tags":["石纹","大理石","端砚","层理","文化质感"],"relatedIds":[149,76,151],"params":[{"key":"stoneType","label":"石材类型","type":"select","value":"marble"},{"key":"veinDirection","label":"纹路方向","type":"number","value":"30"},{"key":"opacity","label":"不透明度","type":"number","value":"8"}],"source":"自然纹理"},
  {"id":151,"name":"金属氧化","nameEn":"Metal Oxidation Texture","category":"textures","subcategory":"时间纹理","description":"金属氧化模拟铜铁等金属表面的锈蚀和氧化层，表现为不规则的色斑和颗粒。金属氧化暗示「时间流逝」和「物质衰变」，与铜绿色有直接关联。建议氧化面积5%-15%、不透明度10%-20%，在档案设计中可暗示档案的年代感。","tags":["金属","氧化","锈蚀","时间流逝","衰变"],"relatedIds":[150,77,152],"params":[{"key":"oxidationLevel","label":"氧化程度","type":"number","value":"40"},{"key":"spotSize","label":"色斑大小","type":"number","value":"8"},{"key":"opacity","label":"不透明度","type":"number","value":"15"}],"source":"时间纹理"},
  {"id":152,"name":"锈蚀纹理","nameEn":"Rust Texture","category":"textures","subcategory":"时间纹理","description":"锈蚀纹理模拟铁器表面的红棕色锈斑，比金属氧化更浓重更局部。锈蚀暗示「长期暴露」和「缺乏维护」，是极端时间痕迹的表达。建议锈斑面积3%-8%、颜色偏红棕，在档案设计中可用于做旧效果或时间痕迹的强化表达。","tags":["锈蚀","红棕","长期暴露","做旧","时间痕迹"],"relatedIds":[151,77,153],"params":[{"key":"rustColor","label":"锈色","type":"color","value":"#8a4a2a"},{"key":"coverage","label":"覆盖面积","type":"number","value":"5"},{"key":"edgeSoftness","label":"边缘柔和度","type":"number","value":"60"}],"source":"时间纹理"},
  {"id":153,"name":"水渍","nameEn":"Water Stain Texture","category":"textures","subcategory":"痕迹纹理","description":"水渍模拟纸面上被水浸湿后晾干的痕迹，表现为边缘深中间浅的不规则环形。水渍暗示「意外事件」和「不可逆改变」，是纸质档案的典型损伤。建议不透明度5%-10%、边缘加深，在档案设计中可用于做旧效果或档案损伤的模拟。","tags":["水渍","浸湿","意外","不可逆","损伤"],"relatedIds":[152,136,154],"params":[{"key":"stainSize","label":"渍面积","type":"number","value":"60"},{"key":"opacity","label":"不透明度","type":"number","value":"8"},{"key":"edgeDarken","label":"边缘加深","type":"number","value":"20"}],"source":"痕迹纹理"},
  {"id":154,"name":"墨渍","nameEn":"Ink Stain Texture","category":"textures","subcategory":"痕迹纹理","description":"墨渍模拟墨水滴落在纸面上的不规则扩散痕迹，中心浓边缘淡。墨渍暗示「书写痕迹」和「意外溅墨」，与青花料的晕散效果有形式关联。建议不透明度10%-20%、边缘羽化，在档案设计中可用于装饰性墨点或书写痕迹模拟。","tags":["墨渍","溅墨","书写","晕散","意外"],"relatedIds":[153,155,69],"params":[{"key":"stainSize","label":"渍面积","type":"number","value":"15"},{"key":"opacity","label":"不透明度","type":"number","value":"15"},{"key":"feather","label":"羽化程度","type":"number","value":"70"}],"source":"痕迹纹理"},
  {"id":155,"name":"蜡封","nameEn":"Wax Seal Texture","category":"textures","subcategory":"印记纹理","description":"蜡封模拟信件封口的红色蜡印，通常带有纹章或文字印记。蜡封暗示「正式」「密封」和「认证」，是权威性的视觉符号。建议蜡封直径20-30px、颜色使用朱砂红#b83a2a，在档案设计中可用于认证标记或正式文档的封口装饰。","tags":["蜡封","红色","认证","密封","正式"],"relatedIds":[154,78,156],"params":[{"key":"sealDiameter","label":"封径","type":"number","value":"24"},{"key":"sealColor","label":"封色","type":"color","value":"#b83a2a"},{"key":"embossDepth","label":"浮雕深度","type":"number","value":"2"}],"source":"印记纹理"},
  {"id":156,"name":"印章红","nameEn":"Red Seal Stamp Texture","category":"textures","subcategory":"印记纹理","description":"印章红模拟中国书画作品上的红色印章效果，方形或圆形，文字为篆体。印章红是朱砂红在单色约束系统中的唯一合法使用场景，暗示「作者身份」和「真品认证」。建议印章尺寸16-24px、不透明度80%-90%，在档案设计中可用于品牌标识或认证标记。","tags":["印章","篆体","认证","朱砂红","身份"],"relatedIds":[155,78,157],"params":[{"key":"stampSize","label":"印章尺寸","type":"number","value":"20"},{"key":"opacity","label":"不透明度","type":"number","value":"85"},{"key":"shape","label":"形状","type":"select","value":"square"}],"source":"印记纹理"},
  {"id":157,"name":"瓷釉透光","nameEn":"Porcelain Translucency Texture","category":"textures","subcategory":"瓷器纹理","description":"瓷釉透光模拟薄胎瓷器在光线照射下的半透明效果，边缘处光线穿透釉层形成温暖的透光感。透光暗示「精致」和「薄如纸」的工艺极致。建议透光不透明度10%-20%、颜色偏暖白，在档案设计中可用于边缘发光效果或精致感表达。","tags":["透光","薄胎","半透明","精致","边缘光"],"relatedIds":[142,141,158],"params":[{"key":"translucency","label":"透光度","type":"number","value":"15"},{"key":"edgeGlow","label":"边缘光强","type":"number","value":"20"},{"key":"warmth","label":"暖度","type":"number","value":"10"}],"source":"瓷器纹理"},
  {"id":158,"name":"窑火痕迹","nameEn":"Kiln Fire Mark Texture","category":"textures","subcategory":"瓷器纹理","description":"窑火痕迹模拟瓷器在窑内烧制时留下的火焰舔舐痕迹和窑灰落点。痕迹呈不规则的色深区域，暗示「不可控的窑变」和「火的参与」。建议痕迹面积3%-8%、不透明度5%-10%，在档案设计中可用于窑变效果的局部强化。","tags":["窑火","火焰","窑灰","不可控","窑变"],"relatedIds":[157,141,68],"params":[{"key":"markSize","label":"痕迹面积","type":"number","value":"5"},{"key":"opacity","label":"不透明度","type":"number","value":"8"},{"key":"colorShift","label":"色偏","type":"number","value":"15"}],"source":"瓷器纹理"},
  {"id":159,"name":"手写笔触","nameEn":"Handwritten Stroke Texture","category":"textures","subcategory":"人文纹理","description":"手写笔触模拟毛笔或钢笔的手写痕迹，线条粗细变化自然，起笔收笔有锋。手写笔触暗示「人的在场」和「即兴表达」，与印刷体的规整形成对比。建议线宽变化1-3px、不透明度80%-95%，在档案设计中可用于批注、签名或手写标注。","tags":["手写","笔触","毛笔","即兴","人的在场"],"relatedIds":[154,156,160],"params":[{"key":"strokeWidth","label":"笔触宽度","type":"number","value":"2"},{"key":"variation","label":"粗细变化","type":"number","value":"50"},{"key":"opacity","label":"不透明度","type":"number","value":"90"}],"source":"人文纹理"},
  {"id":160,"name":"刻线","nameEn":"Engraved Line Texture","category":"textures","subcategory":"人文纹理","description":"刻线模拟在硬质表面刻划的线条痕迹，线宽均匀、边缘锐利、深度一致。刻线暗示「永久记录」和「不可擦除」，与手写笔触的即兴性形成对比。建议线宽0.5-1px、颜色略深于底色，在档案设计中可用于铭刻文字或永久标记。","tags":["刻线","永久","锐利","不可擦除","铭刻"],"relatedIds":[159,141,127],"params":[{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"},{"key":"depth","label":"刻深","type":"number","value":"1"},{"key":"color","label":"刻线色","type":"color","value":"#3a3835"}],"source":"人文纹理"},
  {"id":161,"name":"竹叶暗示","nameEn":"Bamboo Leaf Hint","category":"cultural","subcategory":"地域编码","description":"竹叶暗示是成都地域的低频编码策略，以2%不透明度的竹叶水印隐含于背景之中。观者感受到成都的氛围但说不清原因，这是氛围式编码的典型手法。建议不透明度不超过3%、位置随机分布，在档案设计中可作为全局背景的隐含地域标识。","tags":["竹叶","低频编码","氛围式","2%透明度","成都"],"relatedIds":[162,7,74],"params":[{"key":"opacity","label":"不透明度","type":"number","value":"2"},{"key":"distribution","label":"分布方式","type":"select","value":"random"},{"key":"leafCount","label":"叶片数","type":"number","value":"5"}],"source":"地域编码"},
  {"id":162,"name":"蜀道标记","nameEn":"Shu Road Marker","category":"cultural","subcategory":"地域编码","description":"蜀道标记以「蜀道」文字列条目嵌入信息面板，作为文化路径的文本式编码。蜀道是四川与外界交通的古道，标记暗示「连接」和「路径」。建议字号8-9px、使用等宽字体，在档案设计中可置于信息面板或面包屑导航中作为地域文本标识。","tags":["蜀道","文本式","文化路径","连接","古道"],"relatedIds":[161,163,73],"params":[{"key":"fontSize","label":"字号","type":"number","value":"9"},{"key":"position","label":"位置","type":"select","value":"panel"},{"key":"encodingType","label":"编码类型","type":"select","value":"text"}],"source":"地域编码"},
  {"id":163,"name":"盆地等高线","nameEn":"Basin Contour Lines","category":"cultural","subcategory":"地域编码","description":"盆地等高线以四川盆地的地形等高线作为装饰性图形元素，是方案B地域编码的标志性手法。等高线暗示「地理拓扑」和「盆地地形」，需要主动联想才能识别。建议线宽0.5px、不透明度5%-8%，在档案设计中可作为背景装饰或覆层图形。","tags":["等高线","盆地","地理拓扑","方案B","地形"],"relatedIds":[162,164,73],"params":[{"key":"lineWidth","label":"线宽","type":"number","value":"0.5"},{"key":"opacity","label":"不透明度","type":"number","value":"6"},{"key":"interval","label":"等高距","type":"number","value":"20"}],"source":"地域编码"},
  {"id":164,"name":"熊猫图标","nameEn":"Panda Icon","category":"cultural","subcategory":"地域编码","description":"熊猫图标以8px极简线描熊猫作为彩蛋式地域编码，需要放大才能识别。熊猫是成都最直白的地域符号，但8px的尺寸使其从「直白」变为「隐秘」。建议图标尺寸8px、不透明度5%-10%，在档案设计中可置于页面角落作为彩蛋。","tags":["熊猫","8px","彩蛋","极简线描","隐秘"],"relatedIds":[163,161,73],"params":[{"key":"iconSize","label":"图标尺寸","type":"number","value":"8"},{"key":"opacity","label":"不透明度","type":"number","value":"8"},{"key":"position","label":"位置","type":"select","value":"corner"}],"source":"地域编码"},
  {"id":165,"name":"蜀锦织纹","nameEn":"Shu Brocade Weave","category":"cultural","subcategory":"地域编码","description":"蜀锦织纹以成都蜀锦的经纬交织图案作为覆层纹理，是地域编码的纹理式手法。蜀锦织纹与丝织纹有直接关联，但更强调地域文化属性。建议纹路间距0.5-1px、不透明度3%-5%，在档案设计中可作为全局覆层纹理暗示蜀地文化。","tags":["蜀锦","织纹","纹理式","经纬","蜀地"],"relatedIds":[148,73,162],"params":[{"key":"weaveType","label":"织纹类型","type":"select","value":"shu-brocade"},{"key":"spacing","label":"纹路间距","type":"number","value":"0.8"},{"key":"opacity","label":"不透明度","type":"number","value":"4"}],"source":"地域编码"},
  {"id":166,"name":"景德镇","nameEn":"Jingdezhen","category":"cultural","subcategory":"瓷都文化","description":"景德镇是青花瓷的产地核心，「瓷都」的文化地位使其成为青花瓷设计不可回避的地理锚点。在档案设计中，景德镇作为元数据字段「产地: 景德镇」出现，是文本式文化编码的标准条目。建议以等宽小字呈现于信息面板。","tags":["景德镇","瓷都","产地","地理锚点","元数据"],"relatedIds":[167,168,44],"params":[{"key":"displayMode","label":"展示模式","type":"select","value":"metadata"},{"key":"fontSize","label":"字号","type":"number","value":"9"},{"key":"encodingLevel","label":"编码等级","type":"select","value":"text"}],"source":"瓷都文化"},
  {"id":167,"name":"四大名窑","nameEn":"Four Great Kilns","category":"cultural","subcategory":"瓷都文化","description":"四大名窑指汝、官、哥、钧、定等宋代名窑体系，是瓷器文化的分类框架。在档案设计中，四大名窑可作为分类代码的命名体系或时间线的节点标注。建议以分类代码格式呈现，如「KN-汝」「KN-官」。","tags":["名窑","汝官哥钧定","分类框架","宋代","窑系"],"relatedIds":[166,168,108],"params":[{"key":"displayFormat","label":"展示格式","type":"select","value":"code"},{"key":"kilnSet","label":"窑系选择","type":"select","value":"song-dynasty"},{"key":"fontSize","label":"字号","type":"number","value":"9"}],"source":"瓷都文化"},
  {"id":168,"name":"丝绸之路","nameEn":"Silk Road","category":"cultural","subcategory":"传播路径","description":"丝绸之路是青花瓷从中国传播至世界的文化路径，钴蓝料沿丝绸之路从波斯传入中国。在档案设计中，丝绸之路可作为时间线的叙事线索或流程图的文化背景。建议以虚线路径呈现于地图式构图中。","tags":["丝绸之路","传播","波斯钴料","文化路径","贸易"],"relatedIds":[169,166,98],"params":[{"key":"displayMode","label":"展示模式","type":"select","value":"timeline"},{"key":"direction","label":"方向","type":"select","value":"east-west"},{"key":"lineStyle","label":"线路样式","type":"select","value":"dashed"}],"source":"传播路径"},
  {"id":169,"name":"茶马古道","nameEn":"Tea Horse Road","category":"cultural","subcategory":"传播路径","description":"茶马古道是连接四川与西藏的古代贸易通道，是成都地域特有的文化路径。在档案设计中，茶马古道可作为地域编码的路径元素，与蜀道标记形成互补。建议以等高线背景上的虚线路径呈现。","tags":["茶马古道","四川","西藏","贸易路径","地域"],"relatedIds":[168,162,163],"params":[{"key":"displayMode","label":"展示模式","type":"select","value":"path"},{"key":"lineStyle","label":"线路样式","type":"select","value":"dotted"},{"key":"encodingLevel","label":"编码等级","type":"select","value":"low"}],"source":"传播路径"},
  {"id":170,"name":"青花之路","nameEn":"Blue & White Road","category":"cultural","subcategory":"传播路径","description":"青花之路是钴蓝料从波斯经丝绸之路传入中国、青花瓷又从中国经海路出口至全球的双向文化流动路径。在档案设计中，青花之路可作为核心叙事线索，连接矿物色系、纹饰演变和贸易历史。建议以双向箭头的时间线呈现。","tags":["青花之路","钴蓝料","双向流动","波斯","海路"],"relatedIds":[168,169,166],"params":[{"key":"direction","label":"方向","type":"select","value":"bidirectional"},{"key":"displayMode","label":"展示模式","type":"select","value":"timeline"},{"key":"narrativeFocus","label":"叙事焦点","type":"select","value":"cobalt"}],"source":"传播路径"},
  {"id":171,"name":"釉下彩技法","nameEn":"Underglaze Technique","category":"cultural","subcategory":"工艺哲学","description":"釉下彩技法是青花瓷的核心工艺——先在素坯上绘制纹饰，再施透明釉高温烧制。釉下彩意味着「被保护在釉下」，纹饰永不褪色。在档案设计中，釉下彩技法可作为「持久保存」的隐喻，暗示档案的永久性。","tags":["釉下彩","素坯","高温","永不褪色","保护"],"relatedIds":[172,166,67],"params":[{"key":"firingTemp","label":"烧制温度","type":"number","value":"1280"},{"key":"glazeType","label":"釉类型","type":"select","value":"transparent"},{"key":"technique","label":"技法","type":"select","value":"underglaze"}],"source":"工艺哲学"},
  {"id":172,"name":"窑变哲学","nameEn":"Kiln Transformation Philosophy","category":"cultural","subcategory":"工艺哲学","description":"窑变哲学是「可控与不可控」的辩证思考——窑工控制入窑前的所有变量，但出窑结果仍由火决定。窑变不是缺陷而是特征，这一哲学与算法中的随机种子和生成艺术中的涌现行为深层共鸣。在档案设计中可作为设计哲学的引用。","tags":["窑变","可控不可控","火的意志","涌现","辩证"],"relatedIds":[171,68,40],"params":[{"key":"philosophy","label":"哲学立场","type":"select","value":"dialectic"},{"key":"controlLevel","label":"控制等级","type":"number","value":"70"},{"key":"randomness","label":"随机性","type":"number","value":"30"}],"source":"工艺哲学"},
  {"id":173,"name":"五行色","nameEn":"Five Elements Colors","category":"cultural","subcategory":"传统哲学","description":"五行色对应金（白）、木（青）、水（黑）、火（赤）、土（黄）五种元素的传统色彩体系。在单色约束下，仅取木行青色作为主色，其余四行以灰阶等效替代。建议作为色彩命名的文化参考体系，在档案设计中可丰富色彩的文化语义。","tags":["五行","金木水火土","青色","传统哲学","色彩命名"],"relatedIds":[174,65,71],"params":[{"key":"primaryElement","label":"主元素","type":"select","value":"wood"},{"key":"displayMode","label":"展示模式","type":"select","value":"naming"},{"key":"constraint","label":"约束模式","type":"select","value":"monochrome"}],"source":"传统哲学"},
  {"id":174,"name":"八卦纹","nameEn":"Bagua Pattern","category":"cultural","subcategory":"传统哲学","description":"八卦纹由乾、坤、震、巽、坎、离、艮、兑八个三爻卦象组成，是道教宇宙观的核心符号。八卦纹的对称排列与宝相花的放射对称有形式关联。建议以圆形排列呈现八个卦象，在档案设计中可转化为八方位导航或分类图标。","tags":["八卦","道教","卦象","宇宙观","八方位"],"relatedIds":[173,175,13],"params":[{"key":"arrangement","label":"排列方式","type":"select","value":"circular"},{"key":"style","label":"风格","type":"select","value":"line"},{"key":"trigramSet","label":"卦象集","type":"select","value":"fu-xi"}],"source":"传统哲学"},
  {"id":175,"name":"太极图","nameEn":"Taiji Diagram","category":"cultural","subcategory":"传统哲学","description":"太极图由阴阳双鱼互抱构成，黑中有白点、白中有黑点，表达对立统一的哲学。太极图的S形分界线与缠枝莲的S形曲线有形式关联。建议以极低不透明度作为背景装饰，在档案设计中可暗示「双重性对话」的核心哲学。","tags":["太极","阴阳","对立统一","S形","双重性"],"relatedIds":[174,173,1],"params":[{"key":"size","label":"尺寸","type":"number","value":"60"},{"key":"opacity","label":"不透明度","type":"number","value":"5"},{"key":"rotation","label":"旋转","type":"number","value":"0"}],"source":"传统哲学"},
  {"id":176,"name":"书法美学","nameEn":"Calligraphy Aesthetics","category":"cultural","subcategory":"艺术哲学","description":"书法美学强调「意在笔先」「气韵生动」和「计白当黑」，是青花瓷纹饰绘制的审美基础。书法的线条节奏和空间布局直接影响纹饰的构图逻辑。在档案设计中，书法美学可作为文字排版的审美参考，强调笔画的起承转合。","tags":["书法","意在笔先","气韵","计白当黑","线条"],"relatedIds":[177,159,70],"params":[{"key":"scriptType","label":"书体","type":"select","value":"running"},{"key":"aestheticFocus","label":"审美焦点","type":"select","value":"rhythm"},{"key":"appliedTo","label":"应用于","type":"select","value":"typography"}],"source":"艺术哲学"},
  {"id":177,"name":"园林布局","nameEn":"Garden Layout","category":"cultural","subcategory":"空间哲学","description":"园林布局以「移步换景」「借景」「障景」等手法组织空间体验，是中国空间哲学的集大成者。园林的非线性游览路径与方案B的非对称编辑版面有深层共鸣。在档案设计中，园林布局可作为页面导航和内容组织的隐喻。","tags":["园林","移步换景","借景","非线性","空间哲学"],"relatedIds":[178,85,87],"params":[{"key":"layoutStyle","label":"布局风格","type":"select","value":"suzhou"},{"key":"pathType","label":"路径类型","type":"select","value":"winding"},{"key":"viewpointCount","label":"视点数","type":"number","value":"5"}],"source":"空间哲学"},
  {"id":178,"name":"盆景构图","nameEn":"Bonsai Composition","category":"cultural","subcategory":"空间哲学","description":"盆景构图以「缩龙成寸」的手法将自然景观压缩于方寸之间，是微观宇宙的视觉表达。盆景的「缩」与档案的「归档」有形式关联——都是将大世界收纳于小空间。在档案设计中，盆景构图可隐喻卡片式内容的浓缩展示。","tags":["盆景","缩龙成寸","微观宇宙","浓缩","方寸"],"relatedIds":[177,86,92],"params":[{"key":"scale","label":"缩放比","type":"number","value":"0.01"},{"key":"compositionStyle","label":"构图风格","type":"select","value":"asymmetric"},{"key":"negativeSpace","label":"留白比例","type":"number","value":"40"}],"source":"空间哲学"},
  {"id":179,"name":"水墨渲染","nameEn":"Ink Wash Rendering","category":"cultural","subcategory":"艺术哲学","description":"水墨渲染以水和墨的交融产生浓淡干湿的变化，是青花瓷料水晕散的审美原型。水墨的不可完全控制性与窑变哲学一脉相承。在档案设计中，水墨渲染可启发渐变效果和透明度叠加的视觉处理方式。","tags":["水墨","晕散","浓淡干湿","不可控","渐变"],"relatedIds":[176,172,69],"params":[{"key":"inkDensity","label":"墨浓度","type":"number","value":"60"},{"key":"waterRatio","label":"水比例","type":"number","value":"40"},{"key":"spreadRate","label":"扩散率","type":"number","value":"30"}],"source":"艺术哲学"},
  {"id":180,"name":"留白哲学","nameEn":"Philosophy of Negative Space","category":"cultural","subcategory":"艺术哲学","description":"留白哲学强调「无画处皆成妙境」，空白不是缺失而是呼吸和想象的空间。留白与Cantor集的虚实节奏、单色约束的克制美学一脉相承。建议留白面积不少于30%，在档案设计中可作为全局空间策略的核心原则。","tags":["留白","无画处","呼吸","想象","克制"],"relatedIds":[179,33,65],"params":[{"key":"whitespaceRatio","label":"留白比例","type":"number","value":"30"},{"key":"strategy","label":"策略","type":"select","value":"active"},{"key":"breathingRoom","label":"呼吸空间","type":"number","value":"20"}],"source":"艺术哲学"},
  {"id":181,"name":"正交投影","nameEn":"Orthographic Projection","category":"technical","subcategory":"视图系统","description":"正交投影以无透视变形的方式展示物体的正面、侧面和顶面，是建筑和工程制图的标准投影方式。正交投影的「无变形」特性与方案A的「精确保存」态度一致。建议三视图等比例排列，在档案设计中可用于纹饰的技术分析展示。","tags":["正交","三视图","无变形","工程制图","精确"],"relatedIds":[182,95,84],"params":[{"key":"viewCount","label":"视图数","type":"number","value":"3"},{"key":"scale","label":"比例","type":"select","value":"1:1"},{"key":"lineWeight","label":"线宽等级","type":"select","value":"thin"}],"source":"技术框架"},
  {"id":182,"name":"等轴测视图","nameEn":"Isometric View","category":"technical","subcategory":"视图系统","description":"等轴测视图以30°倾斜角展示物体的三维形态，无透视收缩但具有立体感。等轴测视图的「有深度无变形」特性介于正交投影与透视之间。建议X轴和Y轴各倾斜30°，在档案设计中可用于3D纹饰的展示或系统架构的可视化。","tags":["等轴测","30度","立体感","无透视","三维展示"],"relatedIds":[181,95,85],"params":[{"key":"angle","label":"倾斜角","type":"number","value":"30"},{"key":"scale","label":"缩放","type":"number","value":"1"},{"key":"axisStyle","label":"轴样式","type":"select","value":"dashed"}],"source":"技术框架"},
  {"id":183,"name":"12栏网格系统","nameEn":"12-Column Grid System","category":"technical","subcategory":"布局系统","description":"12栏网格系统是CSS Grid实现的12列布局框架，配合gap和margin形成响应式模块化布局。12是2、3、4、6的公倍数，提供最大的布局灵活性。建议gap值16-24px、margin值24-48px，在档案设计中作为前端实现的布局基础。","tags":["CSS Grid","12栏","响应式","模块化","公倍数"],"relatedIds":[81,184,185],"params":[{"key":"columns","label":"栏数","type":"number","value":"12"},{"key":"gap","label":"gap值","type":"number","value":"20"},{"key":"margin","label":"margin值","type":"number","value":"40"}],"source":"技术框架"},
  {"id":184,"name":"CSS变量体系","nameEn":"CSS Variable System","category":"technical","subcategory":"样式系统","description":"CSS变量体系以自定义属性定义全局设计令牌，包括色彩、字号、间距、阴影等。变量命名遵循--color-primary、--spacing-md等语义化规则。建议变量数50-80个以覆盖所有设计参数，在档案设计中作为设计令牌的CSS实现。","tags":["CSS变量","自定义属性","设计令牌","语义化","全局"],"relatedIds":[183,200,61],"params":[{"key":"variableCount","label":"变量数","type":"number","value":"65"},{"key":"namingConvention","label":"命名规则","type":"select","value":"semantic"},{"key":"scope","label":"作用域","type":"select","value":"global"}],"source":"技术框架"},
  {"id":185,"name":"响应式断点","nameEn":"Responsive Breakpoints","category":"technical","subcategory":"布局系统","description":"响应式断点定义不同屏幕宽度下的布局切换点：移动端<768px、平板768-1024px、桌面>1024px。断点设置影响12栏网格的列数和间距调整。建议三个断点以保持简洁，在档案设计中确保离线档案在不同设备上的可读性。","tags":["响应式","断点","移动端","平板","桌面"],"relatedIds":[183,184,186],"params":[{"key":"mobile","label":"移动端断点","type":"number","value":"768"},{"key":"tablet","label":"平板断点","type":"number","value":"1024"},{"key":"desktop","label":"桌面断点","type":"number","value":"1440"}],"source":"技术框架"},
  {"id":186,"name":"组件化架构","nameEn":"Component Architecture","category":"technical","subcategory":"架构系统","description":"组件化架构将UI拆分为独立可复用的组件，每个组件包含结构、样式和逻辑。组件层级从原子（按钮）到分子（卡片）到有机体（面板），遵循原子设计方法论。建议组件粒度适中、接口清晰，在档案设计中确保UI的一致性和可维护性。","tags":["组件化","原子设计","可复用","一致性","可维护"],"relatedIds":[187,183,184],"params":[{"key":"methodology","label":"方法论","type":"select","value":"atomic-design"},{"key":"componentCount","label":"组件数","type":"number","value":"40"},{"key":"granularity","label":"粒度","type":"select","value":"medium"}],"source":"技术框架"},
  {"id":187,"name":"状态管理","nameEn":"State Management","category":"technical","subcategory":"架构系统","description":"状态管理集中管理应用的全局状态，包括当前选中的纹饰、色彩方案、参数值等。状态变更通过dispatch触发、通过selector读取，确保数据流的单向性和可预测性。建议使用轻量级状态管理方案，在档案设计中确保参数面板与视觉区域的同步。","tags":["状态","全局","单向数据流","可预测","同步"],"relatedIds":[186,188,184],"params":[{"key":"approach","label":"方案","type":"select","value":"zustand"},{"key":"stateCount","label":"状态数","type":"number","value":"20"},{"key":"persistence","label":"持久化","type":"select","value":"local-storage"}],"source":"技术框架"},
  {"id":188,"name":"路由系统","nameEn":"Routing System","category":"technical","subcategory":"架构系统","description":"路由系统管理页面间的导航和URL状态，支持嵌套路由和动态参数。在离线档案中，路由对应档案的层级结构：分类>子类>条目。建议使用基于文件的路由以保持简洁，在档案设计中确保面包屑导航与URL路径的一致性。","tags":["路由","导航","URL状态","嵌套","层级"],"relatedIds":[187,58,186],"params":[{"key":"approach","label":"方案","type":"select","value":"react-router"},{"key":"routeCount","label":"路由数","type":"number","value":"15"},{"key":"mode","label":"模式","type":"select","value":"hash"}],"source":"技术框架"},
  {"id":189,"name":"CI/CD流水线","nameEn":"CI/CD Pipeline","category":"technical","subcategory":"部署系统","description":"CI/CD流水线自动化代码的构建、测试和部署流程。push触发构建、lint和typecheck通过后自动部署到CDN。建议构建时间控制在2分钟以内，在档案设计中确保代码变更能快速安全地反映到线上。","tags":["CI/CD","自动化","构建","部署","流水线"],"relatedIds":[190,191,188],"params":[{"key":"platform","label":"平台","type":"select","value":"github-actions"},{"key":"buildTime","label":"构建时间","type":"number","value":"120"},{"key":"deployTarget","label":"部署目标","type":"select","value":"cloudflare-pages"}],"source":"技术框架"},
  {"id":190,"name":"CDN分发","nameEn":"CDN Distribution","category":"technical","subcategory":"部署系统","description":"CDN分发将静态资源缓存到全球边缘节点，用户从最近节点获取资源以降低延迟。对于离线档案项目，CDN确保全球用户快速访问。建议缓存策略长期缓存静态资源、短期缓存HTML，在档案设计中确保首屏加载时间<2秒。","tags":["CDN","边缘节点","缓存","延迟","全球访问"],"relatedIds":[189,191,192],"params":[{"key":"provider","label":"提供商","type":"select","value":"cloudflare"},{"key":"cacheTTL","label":"缓存时间","type":"number","value":"86400"},{"key":"compression","label":"压缩","type":"select","value":"brotli"}],"source":"技术框架"},
  {"id":191,"name":"HTTPS配置","nameEn":"HTTPS Configuration","category":"technical","subcategory":"安全系统","description":"HTTPS配置确保所有通信加密，SSL/TLS证书由平台自动签发和续期。HTTPS是现代Web的安全基线，也是Service Worker和PWA的必要条件。建议使用HSTS头部强制HTTPS，在档案设计中确保用户数据的安全传输。","tags":["HTTPS","SSL","加密","安全","证书"],"relatedIds":[190,192,189],"params":[{"key":"certProvider","label":"证书提供商","type":"select","value":"lets-encrypt"},{"key":"hsts","label":"HSTS","type":"select","value":"enabled"},{"key":"tlsVersion","label":"TLS版本","type":"select","value":"1.3"}],"source":"技术框架"},
  {"id":192,"name":"性能优化","nameEn":"Performance Optimization","category":"technical","subcategory":"质量系统","description":"性能优化通过代码分割、懒加载、资源压缩、缓存策略等手段提升页面加载和交互速度。对于离线档案项目，首屏加载和动画流畅度是关键指标。建议Lighthouse Performance评分>90，在档案设计中确保流畅的用户体验。","tags":["性能","代码分割","懒加载","压缩","Lighthouse"],"relatedIds":[193,190,184],"params":[{"key":"targetScore","label":"目标评分","type":"number","value":"90"},{"key":"strategy","label":"策略","type":"select","value":"progressive"},{"key":"bundleSize","label":"包大小限制","type":"number","value":"200"}],"source":"技术框架"},
  {"id":193,"name":"Lighthouse审计","nameEn":"Lighthouse Audit","category":"technical","subcategory":"质量系统","description":"Lighthouse审计自动评估Web应用的Performance、Accessibility、Best Practices和SEO四项指标。审计结果以0-100分呈现，每项给出具体的优化建议。建议每次部署前运行审计，在档案设计中作为质量门禁确保上线标准。","tags":["Lighthouse","审计","评分","质量门禁","四项指标"],"relatedIds":[192,194,195],"params":[{"key":"performanceTarget","label":"Performance目标","type":"number","value":"90"},{"key":"accessibilityTarget","label":"Accessibility目标","type":"number","value":"95"},{"key":"seoTarget","label":"SEO目标","type":"number","value":"90"}],"source":"技术框架"},
  {"id":194,"name":"Web Analytics","nameEn":"Web Analytics","category":"technical","subcategory":"分析系统","description":"Web Analytics收集和分析用户访问数据，包括页面浏览量、用户来源、交互行为等。在离线档案项目中，Analytics帮助理解用户如何探索设计概念数据库。建议使用隐私友好的分析方案，在档案设计中作为用户行为洞察的工具。","tags":["分析","数据","用户行为","隐私","洞察"],"relatedIds":[193,195,190],"params":[{"key":"provider","label":"提供商","type":"select","value":"cloudflare-analytics"},{"key":"privacyMode","label":"隐私模式","type":"select","value":"anonymous"},{"key":"trackEvents","label":"事件追踪","type":"select","value":"minimal"}],"source":"技术框架"},
  {"id":195,"name":"SEO元数据","nameEn":"SEO Metadata","category":"technical","subcategory":"发现系统","description":"SEO元数据包括title、description、Open Graph标签和结构化数据，确保搜索引擎和社交媒体正确索引和展示页面。对于离线档案项目，SEO确保设计概念可被搜索发现。建议每个页面有独特的title和description，在档案设计中提升内容的可发现性。","tags":["SEO","元数据","Open Graph","结构化数据","可发现"],"relatedIds":[194,196,193],"params":[{"key":"titleFormat","label":"标题格式","type":"text","value":"{name} | 青花瓷离线档案"},{"key":"ogImage","label":"OG图片","type":"select","value":"auto"},{"key":"structuredData","label":"结构化数据","type":"select","value":"json-ld"}],"source":"技术框架"},
  {"id":196,"name":"无障碍访问","nameEn":"Accessibility","category":"technical","subcategory":"质量系统","description":"无障碍访问确保所有用户包括视障、听障和运动障碍者都能使用Web应用。关键要求包括：色彩对比度>4.5:1、所有交互可键盘操作、图片有alt文本。建议Lighthouse Accessibility评分>95，在档案设计中确保设计概念数据库的包容性。","tags":["无障碍","对比度","键盘操作","alt文本","包容性"],"relatedIds":[193,197,195],"params":[{"key":"contrastRatio","label":"对比度","type":"number","value":"4.5"},{"key":"focusIndicator","label":"焦点指示","type":"select","value":"visible"},{"key":"screenReader","label":"屏幕阅读器","type":"select","value":"compatible"}],"source":"技术框架"},
  {"id":197,"name":"国际化","nameEn":"Internationalization","category":"technical","subcategory":"内容系统","description":"国际化（i18n）使应用支持多语言，包括中文和英文的双语界面。所有用户可见文本抽取为语言包，通过locale切换。建议使用ICU消息格式处理复数和性别，在档案设计中确保中英双语内容的一致展示。","tags":["国际化","i18n","双语","语言包","locale"],"relatedIds":[196,110,198],"params":[{"key":"locales","label":"支持语言","type":"text","value":"zh,en"},{"key":"defaultLocale","label":"默认语言","type":"select","value":"zh"},{"key":"messageFormat","label":"消息格式","type":"select","value":"icu"}],"source":"技术框架"},
  {"id":198,"name":"暗色模式","nameEn":"Dark Mode","category":"technical","subcategory":"样式系统","description":"暗色模式提供深色背景的界面变体，与色调反转的视觉逻辑一致。暗色模式使用冷灰阶#2a2e35为底色、钴蓝#1a3a6b为强调色，模拟夜间屏幕的视觉体验。建议通过CSS变量和media query自动切换，在档案设计中可作为方案B的默认模式。","tags":["暗色模式","深色背景","冷灰阶","自动切换","方案B"],"relatedIds":[199,64,66],"params":[{"key":"bgColor","label":"背景色","type":"color","value":"#1a1e25"},{"key":"textColor","label":"文字色","type":"color","value":"#e0e4e8"},{"key":"switchMode","label":"切换方式","type":"select","value":"system"}],"source":"技术框架"},
  {"id":199,"name":"动画系统","nameEn":"Animation System","category":"technical","subcategory":"交互系统","description":"动画系统定义页面元素的过渡和运动规则，包括入场动画、悬停反馈和页面切换。动画应遵循「有目的的运动」原则——每个动画都服务于信息传达而非纯装饰。建议过渡时长200-400ms、缓动函数ease-out，在档案设计中确保动画的克制和功能性。","tags":["动画","过渡","缓动","有目的","克制"],"relatedIds":[198,184,192],"params":[{"key":"duration","label":"默认时长","type":"number","value":"300"},{"key":"easing","label":"缓动函数","type":"select","value":"ease-out"},{"key":"reducedMotion","label":"减少动画","type":"select","value":"respect"}],"source":"技术框架"},
  {"id":200,"name":"设计令牌","nameEn":"Design Tokens","category":"technical","subcategory":"样式系统","description":"设计令牌是设计决策的最小原子单元，以键值对形式存储色彩、字号、间距、阴影等参数。设计令牌是CSS变量体系的上游来源，确保设计与代码的一致性。建议令牌数80-120个以覆盖所有设计参数，在档案设计中作为设计与开发的唯一真相来源。","tags":["设计令牌","原子单元","键值对","一致性","唯一真相"],"relatedIds":[184,198,61],"params":[{"key":"tokenCount","label":"令牌数","type":"number","value":"100"},{"key":"format","label":"格式","type":"select","value":"json"},{"key":"platforms","label":"目标平台","type":"text","value":"css,ios,android"}],"source":"技术框架"}
